{"version":3,"file":"index.node.esm.js","sources":["../../src/core/error.ts","../../src/core/version.ts","../../src/logger.ts","../../src/network/transport.ts","../../src/network/rest/fetch.ts","../../src/util/url.ts","../../src/network/rest/restTransport.ts","../../src/network/stream/streamTransport.ts","../../src/network/stream/websocket.ts","../../src/cache/EntityDataObject.ts","../../src/cache/InMemoryCacheProvider.ts","../../src/cache/EntityNode.ts","../../src/cache/ResultTree.ts","../../src/cache/ImpactedQueryRefsAccumulator.ts","../../src/cache/ResultTreeProcessor.ts","../../src/cache/Cache.ts","../../src/core/AppCheckTokenProvider.ts","../../src/core/FirebaseAuthProvider.ts","../../src/api/Reference.ts","../../src/cache/cacheUtils.ts","../../src/util/encoder.ts","../../src/core/query/QueryManager.ts","../../src/network/manager.ts","../../src/api/Mutation.ts","../../src/api/DataConnect.ts","../../src/register.ts","../../src/core/query/queryOptions.ts","../../src/api/query.ts","../../src/util/validateArgs.ts","../../src/core/query/subscribe.ts","../../src/index.node.ts"],"sourcesContent":["/**\n * @license\n * Copyright 2024 Google LLC\n *\n * Licensed under the Apache License, Version 2.0 (the \"License\");\n * you may not use this file except in compliance with the License.\n * You may obtain a copy of the License at\n *\n *   http://www.apache.org/licenses/LICENSE-2.0\n *\n * Unless required by applicable law or agreed to in writing, software\n * distributed under the License is distributed on an \"AS IS\" BASIS,\n * WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\n * See the License for the specific language governing permissions and\n * limitations under the License.\n */\n\nimport { FirebaseError } from '@firebase/util';\n\nexport type DataConnectErrorCode =\n  | 'other'\n  | 'already-initialized'\n  | 'not-initialized'\n  | 'not-supported'\n  | 'invalid-argument'\n  | 'partial-error'\n  | 'unauthorized';\n\nexport type Code = DataConnectErrorCode;\n\nexport const Code = {\n  OTHER: 'other' as DataConnectErrorCode,\n  ALREADY_INITIALIZED: 'already-initialized' as DataConnectErrorCode,\n  NOT_INITIALIZED: 'not-initialized' as DataConnectErrorCode,\n  NOT_SUPPORTED: 'not-supported' as DataConnectErrorCode,\n  INVALID_ARGUMENT: 'invalid-argument' as DataConnectErrorCode,\n  PARTIAL_ERROR: 'partial-error' as DataConnectErrorCode,\n  UNAUTHORIZED: 'unauthorized' as DataConnectErrorCode\n};\n\n/** An error returned by a DataConnect operation. */\nexport class DataConnectError extends FirebaseError {\n  /** @internal */\n  readonly name: string = 'DataConnectError';\n\n  constructor(code: Code, message: string) {\n    super(code, message);\n\n    // Ensure the instanceof operator works as expected on subclasses of Error.\n    // See https://developer.mozilla.org/en-US/docs/Web/JavaScript/Reference/Global_Objects/Error#custom_error_types\n    // and https://www.typescriptlang.org/docs/handbook/release-notes/typescript-2-2.html#support-for-newtarget\n    Object.setPrototypeOf(this, DataConnectError.prototype);\n  }\n\n  /** @internal */\n  toString(): string {\n    return `${this.name}[code=${this.code}]: ${this.message}`;\n  }\n}\n\n/** An error returned by a DataConnect operation. */\nexport class DataConnectOperationError extends DataConnectError {\n  /** @internal */\n  readonly name: string = 'DataConnectOperationError';\n\n  /** The response received from the backend. */\n  readonly response: DataConnectOperationFailureResponse;\n\n  /** @hideconstructor */\n  constructor(message: string, response: DataConnectOperationFailureResponse) {\n    super(Code.PARTIAL_ERROR, message);\n    this.response = response;\n  }\n}\n\nexport interface DataConnectOperationFailureResponse {\n  // The \"data\" provided by the backend in the response message.\n  //\n  // Will be `undefined` if no \"data\" was provided in the response message.\n  // Otherwise, will be `null` if `null` was explicitly specified as the \"data\"\n  // in the response message. Otherwise, will be the value of the \"data\"\n  // specified as the \"data\" in the response message\n  readonly data?: Record<string, unknown> | null;\n\n  // The list of errors provided by the backend in the response message.\n  readonly errors: DataConnectOperationFailureResponseErrorInfo[];\n}\n\n// Information about the error, as provided in the response from the backend.\n// See https://spec.graphql.org/draft/#sec-Errors\nexport interface DataConnectOperationFailureResponseErrorInfo {\n  // The error message.\n  readonly message: string;\n\n  // The path of the field in the response data to which this error relates.\n  // String values in this array refer to field names. Numeric values in this\n  // array always satisfy `Number.isInteger()` and refer to the index in an\n  // array.\n  readonly path: Array<string | number>;\n}\n","/**\n * @license\n * Copyright 2024 Google LLC\n *\n * Licensed under the Apache License, Version 2.0 (the \"License\");\n * you may not use this file except in compliance with the License.\n * You may obtain a copy of the License at\n *\n *   http://www.apache.org/licenses/LICENSE-2.0\n *\n * Unless required by applicable law or agreed to in writing, software\n * distributed under the License is distributed on an \"AS IS\" BASIS,\n * WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\n * See the License for the specific language governing permissions and\n * limitations under the License.\n */\n\n/** The semver (www.semver.org) version of the SDK. */\nexport let SDK_VERSION = '';\n\n/**\n * SDK_VERSION should be set before any database instance is created\n * @internal\n */\nexport function setSDKVersion(version: string): void {\n  SDK_VERSION = version;\n}\n","/**\n * @license\n * Copyright 2024 Google LLC\n *\n * Licensed under the Apache License, Version 2.0 (the \"License\");\n * you may not use this file except in compliance with the License.\n * You may obtain a copy of the License at\n *\n *   http://www.apache.org/licenses/LICENSE-2.0\n *\n * Unless required by applicable law or agreed to in writing, software\n * distributed under the License is distributed on an \"AS IS\" BASIS,\n * WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\n * See the License for the specific language governing permissions and\n * limitations under the License.\n */\nimport { Logger, LogLevelString } from '@firebase/logger';\n\nimport { SDK_VERSION } from './core/version';\n\nconst logger = new Logger('@firebase/data-connect');\nexport function setLogLevel(logLevel: LogLevelString): void {\n  logger.setLogLevel(logLevel);\n}\nexport function logDebug(msg: string): void {\n  logger.debug(`DataConnect (${SDK_VERSION}): ${msg}`);\n}\n\nexport function logError(msg: string): void {\n  logger.error(`DataConnect (${SDK_VERSION}): ${msg}`);\n}\n","/**\n * @license\n * Copyright 2024 Google LLC\n *\n * Licensed under the Apache License, Version 2.0 (the \"License\");\n * you may not use this file except in compliance with the License.\n * You may obtain a copy of the License at\n *\n *   http://www.apache.org/licenses/LICENSE-2.0\n *\n * Unless required by applicable law or agreed to in writing, software\n * distributed under the License is distributed on an \"AS IS\" BASIS,\n * WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\n * See the License for the specific language governing permissions and\n * limitations under the License.\n */\n\nimport { DataConnectOptions, TransportOptions } from '../api/DataConnect';\nimport { AppCheckTokenProvider } from '../core/AppCheckTokenProvider';\nimport { Code, DataConnectError } from '../core/error';\nimport { AuthTokenProvider } from '../core/FirebaseAuthProvider';\nimport { SDK_VERSION } from '../core/version';\nimport { logDebug } from '../logger';\n\n/**\n * enum representing different flavors of the SDK used by developers\n * use the CallerSdkType for type-checking, and the CallerSdkTypeEnum for value-checking/assigning\n */\nexport type CallerSdkType =\n  | 'Base' // Core JS SDK\n  | 'Generated' // Generated JS SDK\n  | 'TanstackReactCore' // Tanstack non-generated React SDK\n  | 'GeneratedReact' // Generated React SDK\n  | 'TanstackAngularCore' // Tanstack non-generated Angular SDK\n  | 'GeneratedAngular'; // Generated Angular SDK\nexport const CallerSdkTypeEnum = {\n  Base: 'Base', // Core JS SDK\n  Generated: 'Generated', // Generated JS SDK\n  TanstackReactCore: 'TanstackReactCore', // Tanstack non-generated React SDK\n  GeneratedReact: 'GeneratedReact', // Tanstack non-generated Angular SDK\n  TanstackAngularCore: 'TanstackAngularCore', // Tanstack non-generated Angular SDK\n  GeneratedAngular: 'GeneratedAngular' // Generated Angular SDK\n} as const;\n\nexport interface DataConnectEntityArray {\n  entityIds: string[];\n}\n\nexport interface DataConnectSingleEntity {\n  entityId: string;\n}\n\nexport type DataConnectExtension = {\n  path: Array<string | number>;\n} & (DataConnectEntityArray | DataConnectSingleEntity);\n\n/** @internal */\nexport interface DataConnectMaxAge {\n  maxAge: string;\n}\n\n/** @internal */\nexport type DataConnectExtensionWithMaxAge = {\n  path: Array<string | number>;\n} & (DataConnectEntityArray | DataConnectSingleEntity | DataConnectMaxAge);\n\nexport interface Extensions {\n  dataConnect?: DataConnectExtension[];\n}\n\n/** @internal */\nexport interface ExtensionsWithMaxAge {\n  dataConnect?: DataConnectExtensionWithMaxAge[];\n}\n\n/** @internal */\nexport interface DataConnectResponse<T> {\n  data: T;\n  errors: Error[];\n  extensions: Extensions;\n}\n\n/** @internal */\nexport interface DataConnectResponseWithMaxAge<T> {\n  data: T;\n  errors: Error[];\n  extensions: ExtensionsWithMaxAge;\n}\n\n/**\n * Observer defined by the Query Layer for receiving notifications from the Transport Layer.\n * @internal\n */\nexport interface SubscribeObserver<Data> {\n  onData(response: DataConnectResponse<Data>): Promise<void> | void;\n  onDisconnect(code: string, reason: string): void;\n  onError(error: Error): void;\n}\n\n/**\n * Interface defining the external API of the transport layer.\n * @internal\n */\nexport interface DataConnectTransportInterface {\n  /**\n   * Invoke a query execution request.\n   * @param queryName The name of the query to execute.\n   * @param body The variables associated with the query.\n   * @returns A promise resolving to the DataConnectResponse.\n   */\n  invokeQuery<Data, Variables>(\n    queryName: string,\n    body?: Variables\n  ): Promise<DataConnectResponseWithMaxAge<Data>>;\n\n  /**\n   * Invoke a mutation execution request.\n   * @param queryName The name of the mutation to execute.\n   * @param body The variables associated with the mutation.\n   * @returns A promise resolving to the DataConnectResponse.\n   */\n  invokeMutation<Data, Variables>(\n    queryName: string,\n    body?: Variables\n  ): Promise<DataConnectResponse<Data>>;\n\n  /**\n   * Subscribes to a query to receive push notifications of updates.\n   * @param observer the observer passed to the transport layer to notify the query layer of events.\n   * @param queryName The name of the query to subscribe to.\n   * @param body The variables associated with the subscription.\n   */\n  invokeSubscribe<Data, Variables>(\n    observer: SubscribeObserver<Data>,\n    queryName: string,\n    body?: Variables\n  ): void;\n\n  /**\n   * Unsubscribes from an active subscription.\n   * @param queryName The name of the query to unsubscribe from.\n   * @param body The variables associated with the subscription.\n   */\n  invokeUnsubscribe<Variables>(queryName: string, body?: Variables): void;\n\n  /**\n   * Configures the transport to use a local Data Connect emulator.\n   * @param host The host address of the emulator (e.g., '127.0.0.1').\n   * @param port The port number the emulator is listening on.\n   * @param sslEnabled Whether to use SSL (HTTPS/WSS) for the emulator connection.\n   */\n  useEmulator(host: string, port?: number, sslEnabled?: boolean): void;\n\n  /**\n   * Callback invoked when the Firebase Auth token is refreshed or changed. Note that this callback\n   * is called immediately asynchronously when the Auth Provider is initialized to provide\n   * the initial auth state.\n   * @param token The new access token or null if signed out.\n   */\n  onAuthTokenChanged: (token: string | null) => void;\n\n  /**\n   * Internal method to set the SDK type for metrics and logging purposes.\n   * @param callerSdkType The type of SDK making the call (e.g., generated vs base).\n   */\n  _setCallerSdkType(callerSdkType: CallerSdkType): void;\n}\n\n/**\n * Type signature of a transport class constructor.\n * @internal\n */\nexport type TransportClass = new (\n  options: DataConnectOptions,\n  apiKey?: string,\n  appId?: string,\n  authProvider?: AuthTokenProvider,\n  appCheckProvider?: AppCheckTokenProvider,\n  transportOptions?: TransportOptions,\n  _isUsingGen?: boolean,\n  _callerSdkType?: CallerSdkType\n) => DataConnectTransportInterface;\n\n/**\n * Constructs the value for the X-Goog-Api-Client header\n * @internal\n */\nexport function getGoogApiClientValue(\n  isUsingGen: boolean,\n  callerSdkType: CallerSdkType\n): string {\n  let str = 'gl-js/ fire/' + SDK_VERSION;\n  if (\n    callerSdkType !== CallerSdkTypeEnum.Base &&\n    callerSdkType !== CallerSdkTypeEnum.Generated\n  ) {\n    str += ' js/' + callerSdkType.toLowerCase();\n  } else if (isUsingGen || callerSdkType === CallerSdkTypeEnum.Generated) {\n    str += ' js/gen';\n  }\n  return str;\n}\n\n/**\n * The base class for all DataConnectTransportInterface implementations. Handles common logic such as\n * URL construction, auth token management, and emulator usage. Concrete transport implementations\n * should extend this class and implement the abstract {@link DataConnectTransportInterface} methods.\n * @internal\n */\nexport abstract class AbstractDataConnectTransport\n  implements DataConnectTransportInterface\n{\n  protected _host = '';\n  protected _port: number | undefined;\n  protected _location = 'l';\n  protected _connectorName = '';\n  /** The resource path for requests from this Data Connect instance. */\n  protected _connectorResourcePath: string;\n  protected _secure = true;\n  protected _project = 'p';\n  protected _serviceName: string;\n  protected _authToken: string | null = null;\n  protected _appCheckToken: string | null | undefined = null;\n  protected _lastToken: string | null = null;\n  protected _isUsingEmulator = false;\n\n  constructor(\n    options: DataConnectOptions,\n    protected apiKey?: string | undefined,\n    protected appId?: string | null,\n    protected authProvider?: AuthTokenProvider | undefined,\n    protected appCheckProvider?: AppCheckTokenProvider | undefined,\n    transportOptions?: TransportOptions | undefined,\n    protected _isUsingGen = false,\n    protected _callerSdkType: CallerSdkType = CallerSdkTypeEnum.Base\n  ) {\n    if (transportOptions) {\n      if (typeof transportOptions.port === 'number') {\n        this._port = transportOptions.port;\n      }\n      if (typeof transportOptions.sslEnabled !== 'undefined') {\n        this._secure = transportOptions.sslEnabled;\n      }\n      this._host = transportOptions.host;\n    }\n    const { location, projectId: project, connector, service } = options;\n    if (location) {\n      this._location = location;\n    }\n    if (project) {\n      this._project = project;\n    }\n    this._serviceName = service;\n    if (!connector) {\n      throw new DataConnectError(\n        Code.INVALID_ARGUMENT,\n        'Connector Name required!'\n      );\n    }\n    this._connectorName = connector;\n    this._connectorResourcePath = `projects/${this._project}/locations/${this._location}/services/${this._serviceName}/connectors/${this._connectorName}`;\n    this.authProvider?.addTokenChangeListener(token => {\n      logDebug(`New Token Available: ${token}`);\n      this.onAuthTokenChanged(token);\n    });\n    this.appCheckProvider?.addTokenChangeListener(result => {\n      const { token } = result;\n      logDebug(`New App Check Token Available: ${token}`);\n      this._appCheckToken = token;\n    });\n  }\n\n  /** Get the endpoint URL this transport should use to communicate with the backend. */\n  abstract get endpointUrl(): string;\n\n  useEmulator(host: string, port?: number, isSecure?: boolean): void {\n    this._host = host;\n    this._isUsingEmulator = true;\n    if (typeof port === 'number') {\n      this._port = port;\n    }\n    if (typeof isSecure !== 'undefined') {\n      this._secure = isSecure;\n    }\n  }\n\n  async getWithAuth(forceToken = false): Promise<string | null> {\n    let starterPromise: Promise<string | null> = new Promise(resolve =>\n      resolve(this._authToken)\n    );\n    if (this.appCheckProvider) {\n      const appCheckToken = await this.appCheckProvider.getToken();\n      if (appCheckToken) {\n        this._appCheckToken = appCheckToken.token;\n      }\n    }\n    if (this.authProvider) {\n      starterPromise = this.authProvider\n        .getToken(/*forceToken=*/ forceToken)\n        .then(data => {\n          if (!data) {\n            return null;\n          }\n          this._authToken = data.accessToken;\n          return this._authToken;\n        });\n    } else {\n      starterPromise = new Promise(resolve => resolve(''));\n    }\n    return starterPromise;\n  }\n\n  async withRetry<T>(\n    promiseFactory: () => Promise<DataConnectResponse<T>>,\n    retry = false\n  ): Promise<DataConnectResponse<T>> {\n    let isNewToken = false;\n    return this.getWithAuth(retry)\n      .then(res => {\n        isNewToken = this._lastToken !== res;\n        this._lastToken = res;\n        return res;\n      })\n      .then(promiseFactory)\n      .catch(err => {\n        // Only retry if the result is unauthorized and the last token isn't the same as the new one.\n        if (\n          'code' in err &&\n          err.code === Code.UNAUTHORIZED &&\n          !retry &&\n          isNewToken\n        ) {\n          logDebug('Retrying due to unauthorized');\n          return this.withRetry(promiseFactory, true);\n        }\n        throw err;\n      });\n  }\n\n  _setLastToken(lastToken: string | null): void {\n    this._lastToken = lastToken;\n  }\n\n  abstract invokeQuery<Data, Variables>(\n    queryName: string,\n    body?: Variables\n  ): Promise<DataConnectResponseWithMaxAge<Data>>;\n\n  abstract invokeMutation<Data, Variables>(\n    queryName: string,\n    body?: Variables\n  ): Promise<DataConnectResponse<Data>>;\n\n  abstract invokeSubscribe<Data, Variables>(\n    observer: SubscribeObserver<Data>,\n    queryName: string,\n    body?: Variables\n  ): void;\n\n  abstract invokeUnsubscribe<Variables>(\n    queryName: string,\n    variables: Variables\n  ): void;\n\n  abstract onAuthTokenChanged(newToken: string | null): void;\n\n  _setCallerSdkType(callerSdkType: CallerSdkType): void {\n    this._callerSdkType = callerSdkType;\n  }\n}\n","/**\n * @license\n * Copyright 2024 Google LLC\n *\n * Licensed under the Apache License, Version 2.0 (the \"License\");\n * you may not use this file except in compliance with the License.\n * You may obtain a copy of the License at\n *\n *   http://www.apache.org/licenses/LICENSE-2.0\n *\n * Unless required by applicable law or agreed to in writing, software\n * distributed under the License is distributed on an \"AS IS\" BASIS,\n * WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\n * See the License for the specific language governing permissions and\n * limitations under the License.\n */\n\nimport { isCloudWorkstation } from '@firebase/util';\n\nimport {\n  CallerSdkType,\n  CallerSdkTypeEnum,\n  DataConnectResponse,\n  Extensions\n} from '..';\nimport {\n  Code,\n  DataConnectError,\n  DataConnectOperationError,\n  DataConnectOperationFailureResponse\n} from '../../core/error';\nimport { SDK_VERSION } from '../../core/version';\nimport { logError } from '../../logger';\n\n/** The fetch implementation to be used by the {@link RESTTransport}. */\nlet connectFetch: typeof fetch | null = globalThis.fetch;\n\n/**\n * This function is ONLY used for testing and for ensuring compatability in environments which may\n * be using a poyfill and/or bundlers. It should not be called by users of the Firebase JS SDK.\n * @internal\n */\nexport function initializeFetch(fetchImpl: typeof fetch): void {\n  connectFetch = fetchImpl;\n}\n\nfunction getGoogApiClientValue(\n  _isUsingGen: boolean,\n  _callerSdkType: CallerSdkType\n): string {\n  let str = 'gl-js/ fire/' + SDK_VERSION;\n  if (\n    _callerSdkType !== CallerSdkTypeEnum.Base &&\n    _callerSdkType !== CallerSdkTypeEnum.Generated\n  ) {\n    str += ' js/' + _callerSdkType.toLowerCase();\n  } else if (_isUsingGen || _callerSdkType === CallerSdkTypeEnum.Generated) {\n    str += ' js/gen';\n  }\n  return str;\n}\nexport interface DataConnectFetchBody<Variables> {\n  name: string;\n  operationName: string;\n  variables: Variables;\n}\nexport async function dcFetch<Data, Variables>(\n  url: string,\n  body: DataConnectFetchBody<Variables>,\n  { signal }: AbortController,\n  appId: string | null | undefined,\n  accessToken: string | null,\n  appCheckToken: string | null | undefined,\n  _isUsingGen: boolean,\n  _callerSdkType: CallerSdkType,\n  _isUsingEmulator: boolean\n): Promise<DataConnectResponse<Data>> {\n  if (!connectFetch) {\n    throw new DataConnectError(Code.OTHER, 'No Fetch Implementation detected!');\n  }\n  const headers: HeadersInit = {\n    'Content-Type': 'application/json',\n    'X-Goog-Api-Client': getGoogApiClientValue(_isUsingGen, _callerSdkType)\n  };\n  if (accessToken) {\n    headers['X-Firebase-Auth-Token'] = accessToken;\n  }\n  if (appId) {\n    headers['x-firebase-gmpid'] = appId;\n  }\n  if (appCheckToken) {\n    headers['X-Firebase-AppCheck'] = appCheckToken;\n  }\n  const bodyStr = JSON.stringify(body);\n  const fetchOptions: RequestInit = {\n    body: bodyStr,\n    method: 'POST',\n    headers,\n    signal\n  };\n  if (isCloudWorkstation(url) && _isUsingEmulator) {\n    fetchOptions.credentials = 'include';\n  }\n\n  let response: Response;\n  try {\n    response = await connectFetch(url, fetchOptions);\n  } catch (err) {\n    const message =\n      err && typeof err === 'object' && 'message' in err\n        ? (err as unknown as Record<string, unknown>)['message']\n        : String(err);\n    throw new DataConnectError(Code.OTHER, 'Failed to fetch: ' + message);\n  }\n  let jsonResponse: JsonResponse<Data>;\n  try {\n    jsonResponse = await response.json();\n  } catch (e) {\n    const message =\n      e && typeof e === 'object' && 'message' in e\n        ? (e as unknown as Record<string, unknown>)['message']\n        : String(e);\n    throw new DataConnectError(\n      Code.OTHER,\n      'Failed to parse JSON response: ' + message\n    );\n  }\n  const message = getErrorMessage(jsonResponse);\n  if (response.status >= 400) {\n    logError('Error while performing request: ' + JSON.stringify(jsonResponse));\n    if (response.status === 401) {\n      throw new DataConnectError(Code.UNAUTHORIZED, message);\n    }\n    throw new DataConnectError(Code.OTHER, message);\n  }\n  if (jsonResponse.errors && jsonResponse.errors.length) {\n    const stringified = JSON.stringify(jsonResponse.errors);\n    const failureResponse: DataConnectOperationFailureResponse = {\n      errors: jsonResponse.errors,\n      data: jsonResponse.data as Record<string, unknown>\n    };\n    throw new DataConnectOperationError(\n      'DataConnect error while performing request: ' + stringified,\n      failureResponse\n    );\n  }\n  if (!jsonResponse.extensions) {\n    jsonResponse.extensions = {\n      dataConnect: []\n    };\n  }\n  return jsonResponse as DataConnectResponse<Data>;\n}\ninterface JsonResponse<Data> {\n  message?: string;\n  errors: [];\n  data: Record<string, unknown> | Data | null;\n  extensions?: Extensions;\n}\nfunction getErrorMessage(obj: JsonResponse<unknown>): string {\n  if ('message' in obj && obj.message) {\n    return obj.message;\n  }\n  return JSON.stringify(obj);\n}\n","/**\n * @license\n * Copyright 2024 Google LLC\n *\n * Licensed under the Apache License, Version 2.0 (the \"License\");\n * you may not use this file except in compliance with the License.\n * You may obtain a copy of the License at\n *\n *   http://www.apache.org/licenses/LICENSE-2.0\n *\n * Unless required by applicable law or agreed to in writing, software\n * distributed under the License is distributed on an \"AS IS\" BASIS,\n * WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\n * See the License for the specific language governing permissions and\n * limitations under the License.\n */\n\nimport { DataConnectOptions, TransportOptions } from '../api/DataConnect';\nimport { Code, DataConnectError } from '../core/error';\nimport { logError } from '../logger';\n\nexport const PROD_HOST = 'firebasedataconnect.googleapis.com';\nexport const WEBSOCKET_PATH =\n  'ws/google.firebase.dataconnect.v1.ConnectorStreamService';\n\nexport function restUrlBuilder(\n  projectConfig: DataConnectOptions,\n  transportOptions: TransportOptions\n): string {\n  const { connector, location, projectId: project, service } = projectConfig;\n  const { host, sslEnabled, port } = transportOptions;\n  const protocol = sslEnabled ? 'https' : 'http';\n  const realHost = host || PROD_HOST;\n  let baseUrl = `${protocol}://${realHost}`;\n  if (typeof port === 'number') {\n    baseUrl += `:${port}`;\n  } else if (typeof port !== 'undefined') {\n    logError('Port type is of an invalid type');\n    throw new DataConnectError(\n      Code.INVALID_ARGUMENT,\n      'Incorrect type for port passed in!'\n    );\n  }\n  return `${baseUrl}/v1/projects/${project}/locations/${location}/services/${service}/connectors/${connector}`;\n}\n\nexport function websocketUrlBuilder(\n  projectConfig: DataConnectOptions,\n  transportOptions: TransportOptions\n): string {\n  const { location } = projectConfig;\n  const { host, sslEnabled, port } = transportOptions;\n  const protocol = sslEnabled ? 'wss' : 'ws';\n  const realHost = host || PROD_HOST;\n  let baseUrl = `${protocol}://${realHost}`;\n  if (typeof port === 'number') {\n    baseUrl += `:${port}`;\n  } else if (typeof port !== 'undefined') {\n    logError('Port type is of an invalid type');\n    throw new DataConnectError(\n      Code.INVALID_ARGUMENT,\n      'Incorrect type for port passed in!'\n    );\n  }\n  return `${baseUrl}/${WEBSOCKET_PATH}/Connect/locations/${location}`;\n}\n\nexport function addToken(url: string, apiKey?: string): string {\n  if (!apiKey) {\n    return url;\n  }\n  const newUrl = new URL(url);\n  newUrl.searchParams.append('key', apiKey);\n  return newUrl.toString();\n}\n","/**\n * @license\n * Copyright 2024 Google LLC\n *\n * Licensed under the Apache License, Version 2.0 (the \"License\");\n * you may not use this file except in compliance with the License.\n * You may obtain a copy of the License at\n *\n *   http://www.apache.org/licenses/LICENSE-2.0\n *\n * Unless required by applicable law or agreed to in writing, software\n * distributed under the License is distributed on an \"AS IS\" BASIS,\n * WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\n * See the License for the specific language governing permissions and\n * limitations under the License.\n */\n\nimport {\n  CallerSdkType,\n  CallerSdkTypeEnum,\n  DataConnectResponse,\n  DataConnectResponseWithMaxAge,\n  AbstractDataConnectTransport,\n  SubscribeObserver\n} from '..';\nimport { DataConnectOptions, TransportOptions } from '../../api/DataConnect';\nimport { AppCheckTokenProvider } from '../../core/AppCheckTokenProvider';\nimport { Code, DataConnectError } from '../../core/error';\nimport { AuthTokenProvider } from '../../core/FirebaseAuthProvider';\nimport { addToken, restUrlBuilder } from '../../util/url';\n\nimport { dcFetch } from './fetch';\n\n/**\n * Fetch-based REST implementation of {@link AbstractDataConnectTransport}.\n * @internal\n */\nexport class RESTTransport extends AbstractDataConnectTransport {\n  constructor(\n    options: DataConnectOptions,\n    apiKey?: string | undefined,\n    appId?: string | null,\n    authProvider?: AuthTokenProvider | undefined,\n    appCheckProvider?: AppCheckTokenProvider | undefined,\n    transportOptions?: TransportOptions | undefined,\n    _isUsingGen = false,\n    _callerSdkType: CallerSdkType = CallerSdkTypeEnum.Base\n  ) {\n    super(\n      options,\n      apiKey,\n      appId,\n      authProvider,\n      appCheckProvider,\n      transportOptions,\n      _isUsingGen,\n      _callerSdkType\n    );\n  }\n\n  get endpointUrl(): string {\n    return restUrlBuilder(\n      {\n        connector: this._connectorName,\n        location: this._location,\n        projectId: this._project,\n        service: this._serviceName\n      },\n      {\n        host: this._host,\n        sslEnabled: this._secure,\n        port: this._port\n      }\n    );\n  }\n\n  invokeQuery: <Data, Variables>(\n    queryName: string,\n    body?: Variables\n  ) => Promise<DataConnectResponseWithMaxAge<Data>> = <\n    Data,\n    Variables = unknown\n  >(\n    queryName: string,\n    body: Variables\n  ) => {\n    const abortController = new AbortController();\n\n    // TODO(mtewani): Update to proper value\n    const withAuth = this.withRetry(() =>\n      dcFetch<Data, Variables>(\n        addToken(`${this.endpointUrl}:executeQuery`, this.apiKey),\n        {\n          name: this._connectorResourcePath,\n          operationName: queryName,\n          variables: body\n        },\n        abortController,\n        this.appId,\n        this._authToken,\n        this._appCheckToken,\n        this._isUsingGen,\n        this._callerSdkType,\n        this._isUsingEmulator\n      )\n    );\n    return withAuth;\n  };\n\n  invokeMutation: <Data, Variables>(\n    queryName: string,\n    body?: Variables\n  ) => Promise<DataConnectResponse<Data>> = <Data, Variables = unknown>(\n    mutationName: string,\n    body: Variables\n  ) => {\n    const abortController = new AbortController();\n    const taskResult = this.withRetry(() => {\n      return dcFetch<Data, Variables>(\n        addToken(`${this.endpointUrl}:executeMutation`, this.apiKey),\n        {\n          name: this._connectorResourcePath,\n          operationName: mutationName,\n          variables: body\n        },\n        abortController,\n        this.appId,\n        this._authToken,\n        this._appCheckToken,\n        this._isUsingGen,\n        this._callerSdkType,\n        this._isUsingEmulator\n      );\n    });\n    return taskResult;\n  };\n\n  invokeSubscribe<Data, Variables>(\n    observer: SubscribeObserver<Data>,\n    queryName: string,\n    body?: Variables\n  ): void {\n    throw new DataConnectError(\n      Code.NOT_SUPPORTED,\n      'Subscriptions are not supported using REST!'\n    );\n  }\n\n  invokeUnsubscribe<Variables>(queryName: string, body?: Variables): void {\n    throw new DataConnectError(\n      Code.NOT_SUPPORTED,\n      'Unsubscriptions are not supported using REST!'\n    );\n  }\n\n  onAuthTokenChanged(newToken: string | null): void {\n    this._authToken = newToken;\n  }\n}\n","/**\n * @license\n * Copyright 2026 Google LLC\n *\n * Licensed under the Apache License, Version 2.0 (the \"License\");\n * you may not use this file except in compliance with the License.\n * You may obtain a copy of the License at\n *\n * http://www.apache.org/licenses/LICENSE-2.0\n *\n * Unless required by applicable law or agreed to in writing, software\n * distributed under the License is distributed on an \"AS IS\" BASIS,\n * WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\n * See the License for the specific language governing permissions and\n * limitations under the License.\n */\n\nimport { FirebaseError } from '@firebase/util';\n\nimport { DataConnectOptions, TransportOptions } from '../../api/DataConnect';\nimport { AppCheckTokenProvider } from '../../core/AppCheckTokenProvider';\nimport {\n  Code,\n  DataConnectError,\n  DataConnectOperationError,\n  DataConnectOperationFailureResponse\n} from '../../core/error';\nimport { AuthTokenProvider } from '../../core/FirebaseAuthProvider';\nimport { logError, logDebug } from '../../logger';\nimport {\n  AbstractDataConnectTransport,\n  CallerSdkType,\n  CallerSdkTypeEnum,\n  DataConnectResponse,\n  SubscribeObserver,\n  getGoogApiClientValue\n} from '../transport';\n\nimport {\n  CancelStreamRequest,\n  DataConnectStreamRequest,\n  ExecuteStreamRequest,\n  ResumeStreamRequest,\n  StreamRequestHeaders,\n  SubscribeStreamRequest\n} from './wire';\n\n/** The Request ID of the first request over the stream */\nconst FIRST_REQUEST_ID = 1;\n\n/** Time to wait before closing an idle connection (no active subscriptions). */\nconst IDLE_CONNECTION_TIMEOUT_MS = 0; // immediate close\n\n/** Initial reconnect delay in ms */\nconst INITIAL_RECONNECT_DELAY_MS = 1000;\n/** Max reconnect delay in ms */\nconst MAX_RECONNECT_DELAY_MS = 30000;\n/** Max random jitter to add to reconnect delay in ms */\nconst MAX_RECONNECT_JITTER_MS = 500;\n/** Factor to multiply delay by on failure */\nconst RECONNECT_BACKOFF_FACTOR = 1.3;\n/** Max number of reconnection attempts before giving up */\nconst MAX_RECONNECT_ATTEMPTS = 10;\n\n/**\n * A promise returned to the user when invoking an operation via {@linkcode AbstractDataConnectStreamTransport.invokeQuery | invokeQuery}\n * or {@linkcode AbstractDataConnectStreamTransport.invokeMutation | invokeMutation} and the functions\n * that resolve/reject it.\n * @internal\n */\nexport interface InvokeOperationPromise<Data> {\n  responsePromise: Promise<DataConnectResponse<Data>>;\n  resolveFn: (response: DataConnectResponse<Data>) => void;\n  // eslint-disable-next-line @typescript-eslint/no-explicit-any\n  rejectFn: (reason: any) => void;\n}\n\n/**\n * The base class for all Stream Transport implementations.\n * Handles management of logical streams (requests), authentication, data routing to query layer,\n * request optimizations, etc.\n * @internal\n */\nexport abstract class AbstractDataConnectStreamTransport extends AbstractDataConnectTransport {\n  /** Optional callback invoked when the stream closes (gracefully or fatally). */\n  onCloseCallback?: () => void;\n\n  /** True if the physical stream connection is fully open and ready to transmit data. */\n  abstract get streamIsReady(): boolean;\n\n  /** Is the stream currently waiting to close connection? */\n  get isPendingClose(): boolean {\n    return !!this.idleTimeout;\n  }\n\n  /** True if the transport is unable to connect to the server */\n  isUnableToConnect = false;\n\n  /** True if there are active subscriptions on the stream */\n  get hasActiveSubscriptions(): boolean {\n    return this.activeInvokeSubscribeRequests.size > 0;\n  }\n\n  /** True if there are active execute or mutation requests on the stream */\n  get hasActiveExecuteRequests(): boolean {\n    return (\n      this.activeInvokeQueryRequests.size > 0 ||\n      this.activeInvokeMutationRequests.size > 0\n    );\n  }\n\n  constructor(\n    options: DataConnectOptions,\n    protected apiKey?: string | undefined,\n    protected appId?: string | null,\n    protected authProvider?: AuthTokenProvider | undefined,\n    protected appCheckProvider?: AppCheckTokenProvider | undefined,\n    transportOptions?: TransportOptions | undefined,\n    protected _isUsingGen = false,\n    protected _callerSdkType: CallerSdkType = CallerSdkTypeEnum.Base\n  ) {\n    super(\n      options,\n      apiKey,\n      appId,\n      authProvider,\n      appCheckProvider,\n      transportOptions,\n      _isUsingGen,\n      _callerSdkType\n    );\n\n    this.registerBrowserEventListeners();\n  }\n\n  /**\n   * Register event listeners for browser-specific events like online/offline and visibility changes.\n   */\n  private registerBrowserEventListeners(): void {\n    if ('addEventListener' in globalThis) {\n      const listener = this.onOnlineEventListener;\n      globalThis.addEventListener('online', listener);\n      this.removeOnlineEventListener = () =>\n        globalThis.removeEventListener('online', listener);\n    }\n\n    const doc = globalThis.document;\n    if (doc && 'addEventListener' in doc) {\n      const listener = this.onVisibilityChangeEventListener;\n      doc.addEventListener('visibilitychange', listener);\n      this.removeVisibilityChangeEventListener = () =>\n        doc.removeEventListener('visibilitychange', listener);\n    }\n  }\n\n  /**\n   * Remove event listeners registered by {@linkcode AbstractDataConnectStreamTransport.registerBrowserEventListeners | registerBrowserEventListeners()}\n   * for browser-specific events like online/offline and visibility changes.\n   */\n  private cleanupBrowserEventListeners(): void {\n    this.removeVisibilityChangeEventListener?.();\n    this.removeVisibilityChangeEventListener = null;\n    this.removeOnlineEventListener?.();\n    this.removeOnlineEventListener = null;\n  }\n\n  /**\n   * Disposes of the transport instance, cleaning up event listeners and timers,\n   * and closing the connection.\n   */\n  async cleanupAndTerminate(code?: Code, reason?: string): Promise<void> {\n    this.cleanupBrowserEventListeners();\n    this.cancelReconnect();\n    this.cancelClose();\n    this.rejectAllRequests(code ?? Code.OTHER, reason ?? 'Stream disposed.');\n    await this.closeConnection();\n    this.onCloseCallback?.();\n  }\n\n  /**\n   * Open a physical connection to the server.\n   * @returns a promise which resolves when the connection is ready, or rejects if it fails to open.\n   */\n  protected abstract openConnection(): Promise<void>;\n\n  /**\n   * Close the physical connection with the server. Handles no cleanup - simply closes the\n   * implementation-specific connection. On failure to close, the connection is still considered closed.\n   * @returns a promise which resolves when the connection is closed, or rejects if it fails to close.\n   */\n  protected abstract closeConnection(): Promise<void>;\n\n  /**\n   * Queue a {@linkcode DataConnectStreamRequest} to be sent over the stream.\n   * @param requestBody The body of the message to be sent.\n   * @throws DataConnectError if sending fails.\n   */\n  protected abstract sendMessage<Variables>(\n    requestBody: DataConnectStreamRequest<Variables>\n  ): Promise<void>;\n\n  /**\n   * Ensures that that there is an open connection. If there is none, it initiates a new one.\n   * If a connection attempt is already in progress, it returns the existing connection promise.\n   * @returns A promise that resolves when the stream is open and ready.\n   */\n  protected abstract ensureConnection(): Promise<void>;\n\n  /** The Request ID of the next message to be sent. Monotonically increasing sequence number starting at {@linkcode FIRST_REQUEST_ID}. */\n  private requestNumber = FIRST_REQUEST_ID;\n  /**\n   * Generates and returns the next Request ID. Starts at {@linkcode FIRST_REQUEST_ID} and increments\n   * for each request sent.\n   */\n  private nextRequestId(): string {\n    return (this.requestNumber++).toString();\n  }\n\n  /**\n   * Map of query/variables to their active {@linkcode ExecuteStreamRequest} or {@linkcode ResumeStreamRequest}\n   * request bodies. These requests are de-duplicated by query/variables so that there is only one active\n   * request for each query/variables combination.\n   */\n  private activeInvokeQueryRequests = new Map<\n    string,\n    ExecuteStreamRequest<unknown> | ResumeStreamRequest\n  >();\n\n  /**\n   * Map of query/variables to the promises returned to the user, for invokeQuery requests which are\n   * queued and waiting for active request to resolve.\n   */\n  private queuedInvokeQueryRequests = new Map<\n    string,\n    // eslint-disable-next-line @typescript-eslint/no-explicit-any\n    InvokeOperationPromise<any>\n  >();\n\n  /**\n   * Map of mutation/variables to their active {@linkcode ExecuteStreamRequest} request bodies. Mutations\n   * can have more than one active request at a time as they are not idempotent, and therefore should\n   * not be de-duplicated.\n   */\n  private activeInvokeMutationRequests = new Map<\n    string,\n    Array<ExecuteStreamRequest<unknown>>\n  >();\n\n  /**\n   * Map of query/variables to their active {@linkcode SubscribeStreamRequest} request bodies. There\n   * may only be one active request for each query/variables combination.\n   */\n  private activeInvokeSubscribeRequests = new Map<\n    string,\n    SubscribeStreamRequest<unknown>\n  >();\n\n  /**\n   * Map of active {@linkcode ExecuteStreamRequest} RequestIds from {@linkcode invokeQuery} and {@linkcode invokeMutation},\n   * and their corresponding {@linkcode InvokeOperationPromise}.\n   */\n  private executeRequestPromises = new Map<\n    string,\n    // eslint-disable-next-line @typescript-eslint/no-explicit-any\n    InvokeOperationPromise<any>\n  >();\n\n  /**\n   * Map of active {@linkcode ResumeStreamRequest} RequestIds from {@linkcode invokeQuery}, and their\n   * corresponding {@linkcode InvokeOperationPromise}.\n   */\n  private resumeRequestPromises = new Map<\n    string,\n    // eslint-disable-next-line @typescript-eslint/no-explicit-any\n    InvokeOperationPromise<any>\n  >();\n\n  /**\n   * Map of active {@linkcode invokeSubscribe} RequestIds and their corresponding {@linkcode SubscribeObserver}.\n   */\n  private subscribeObservers = new Map<string, SubscribeObserver<unknown>>();\n\n  /**\n   * Map of subscribe RequestIds to deferred unsubscription requests. Used when a client unsubscribes\n   * while a resume request is actively pending.\n   */\n  private pendingCancellations = new Map<\n    string,\n    { operationName: string; variables: unknown }\n  >();\n\n  /** current idle timeout, if any */\n  private idleTimeout: ReturnType<typeof setTimeout> | null = null;\n\n  /** current auth uid. used to detect if a different user logs in */\n  private authUid: string | null | undefined;\n  /** Flag to ensure we wait for the initial auth state once per connection attempt. */\n  private hasWaitedForInitialAuth = false;\n\n  /**\n   * Tracks an {@linkcode invokeMutation} request, storing the request body and creating and storing a\n   * response promise that will be resolved when the response is received.\n   * @returns The tracked {@linkcode InvokeOperationPromise}.\n   *\n   * @remarks\n   * This method returns a promise, but is synchronous.\n   */\n  private trackInvokeMutationRequest<Data>(\n    requestId: string,\n    mapKey: string,\n    executeBody: ExecuteStreamRequest<unknown>\n  ): InvokeOperationPromise<Data> {\n    let resolveFn: (response: DataConnectResponse<Data>) => void;\n    // eslint-disable-next-line @typescript-eslint/no-explicit-any\n    let rejectFn: (reason: any) => void;\n    const responsePromise = new Promise<DataConnectResponse<Data>>(\n      (resolve, reject) => {\n        resolveFn = resolve;\n        rejectFn = reject;\n      }\n    );\n    const executeRequestPromise: InvokeOperationPromise<Data> = {\n      responsePromise,\n      resolveFn: resolveFn!,\n      rejectFn: rejectFn!\n    };\n\n    const activeRequests = this.activeInvokeMutationRequests.get(mapKey) || [];\n    activeRequests.push(executeBody);\n    this.activeInvokeMutationRequests.set(mapKey, activeRequests);\n    this.executeRequestPromises.set(requestId, executeRequestPromise);\n\n    return executeRequestPromise;\n  }\n\n  /**\n   * Tracks an {@linkcode invokeSubscribe} request, storing the request body and the {@linkcode SubscribeObserver}.\n   * @remarks\n   * This method is synchronous.\n   */\n  private trackInvokeSubscribeRequest<Data>(\n    requestId: string,\n    mapKey: string,\n    subscribeBody: SubscribeStreamRequest<unknown>,\n    observer: SubscribeObserver<Data>\n  ): void {\n    this.activeInvokeSubscribeRequests.set(mapKey, subscribeBody);\n    this.subscribeObservers.set(requestId, observer);\n  }\n\n  /**\n   * Cleans up the query execute request tracking data structures, deleting the tracked request and\n   * it's associated promise.\n   */\n  private cleanupInvokeQueryRequest(requestId: string, mapKey: string): void {\n    this.activeInvokeQueryRequests.delete(mapKey);\n    this.executeRequestPromises.delete(requestId);\n    this.resumeRequestPromises.delete(requestId);\n  }\n\n  /**\n   * Cleans up the mutation execute request tracking data structures, deleting the tracked request and\n   * it's associated promise.\n   */\n  private cleanupInvokeMutationRequest(\n    requestId: string,\n    mapKey: string\n  ): void {\n    const executeRequests = this.activeInvokeMutationRequests.get(mapKey);\n    if (executeRequests) {\n      const updatedRequests = executeRequests.filter(\n        request => request.requestId !== requestId\n      );\n      if (updatedRequests.length > 0) {\n        this.activeInvokeMutationRequests.set(mapKey, updatedRequests);\n      } else {\n        this.activeInvokeMutationRequests.delete(mapKey);\n      }\n    }\n    this.executeRequestPromises.delete(requestId);\n  }\n\n  /**\n   * Cleans up the subscribe request tracking data structures, deleting the tracked request and\n   * it's associated promise.\n   */\n  private cleanupInvokeSubscribeRequest(\n    requestId: string,\n    mapKey: string\n  ): void {\n    this.activeInvokeSubscribeRequests.delete(mapKey);\n    this.subscribeObservers.delete(requestId);\n  }\n\n  /** Delay for next reconnection attempt in ms */\n  private reconnectDelayMs = INITIAL_RECONNECT_DELAY_MS;\n  /** Timer for reconnection */\n  private reconnectTimer: ReturnType<typeof setTimeout> | null = null;\n  /** Number of consecutive reconnection attempts */\n  private reconnectAttempts = 0;\n\n  /** Callback to remove online event listener */\n  private removeOnlineEventListener: (() => void) | null = null;\n  /** Callback to remove visibility change event listener */\n  private removeVisibilityChangeEventListener: (() => void) | null = null;\n\n  /**\n   * Short-circuit a reconnection attempt, if one is pending. Triggered when an online event is\n   * dispatched.\n   */\n  onOnlineEventListener = (): void => {\n    if (this.reconnectTimer) {\n      this.cancelReconnect();\n      void this.attemptReconnect();\n    }\n  };\n\n  /**\n   * Short-circuit a reconnection attempt, if one is pending. Triggered when a visibility change\n   * event is dispatched.\n   */\n  onVisibilityChangeEventListener = (): void => {\n    const doc = globalThis.document;\n    if (doc && doc.visibilityState === 'visible' && this.reconnectTimer) {\n      this.cancelReconnect();\n      void this.attemptReconnect();\n    }\n  };\n\n  /**\n   * Cancel reconnecting.\n   */\n  private cancelReconnect(): void {\n    if (this.reconnectTimer) {\n      clearTimeout(this.reconnectTimer);\n      this.reconnectTimer = null;\n    }\n  }\n\n  /**\n   * Starts the backoff timer for reconnection attempts. We use an exponential backoff with randomized\n   * jitter to prevent overwhelming the backend with connection attempts.\n   */\n  private startReconnectBackoff(): void {\n    if (this.reconnectTimer) {\n      return;\n    }\n    if (this.reconnectAttempts++ >= MAX_RECONNECT_ATTEMPTS) {\n      const errorString =\n        'Stream disconnected and could not reconnect - max stream reconnection attempts reached.';\n      logError(errorString);\n      void this.cleanupAndTerminate(Code.OTHER, errorString);\n      return;\n    }\n    const delay = this.reconnectDelayMs;\n    this.reconnectDelayMs = Math.min(\n      this.reconnectDelayMs * RECONNECT_BACKOFF_FACTOR,\n      MAX_RECONNECT_DELAY_MS\n    );\n    const jitter = Math.random() * MAX_RECONNECT_JITTER_MS;\n\n    this.reconnectTimer = setTimeout(() => {\n      this.reconnectTimer = null;\n      void this.attemptReconnect();\n    }, delay + jitter);\n  }\n\n  private async attemptReconnect(): Promise<void> {\n    try {\n      await this.ensureConnection();\n      // reset on success\n      this.reconnectDelayMs = INITIAL_RECONNECT_DELAY_MS;\n      this.reconnectAttempts = 0;\n      await this.retriggerActiveRequests();\n    } catch (e) {\n      if (e instanceof FirebaseError) {\n        logDebug(\n          `Reconnect attempt #${this.reconnectAttempts} failed with Firebase error: ${e.message}. Retrying...`\n        );\n        this.startReconnectBackoff();\n      } else {\n        logError(\n          `Unexpected error during reconnect attempt #${this.reconnectAttempts}: ${e}`\n        );\n        void this.cleanupAndTerminate(\n          Code.OTHER,\n          `Unexpected error during reconnect attempt #${this.reconnectAttempts}: ${e}`\n        );\n      }\n    }\n  }\n\n  /**\n   * Retriggers all active requests on the stream connection - first subscribes, then query executions,\n   * and skip mutations. Used after a successful reconnection.\n   */\n  private async retriggerActiveRequests(): Promise<void> {\n    for (const [_, subscribeBody] of this.activeInvokeSubscribeRequests) {\n      await this.sendRequestMessage(subscribeBody);\n    }\n    for (const [_, requestBody] of this.activeInvokeQueryRequests) {\n      await this.sendRequestMessage(requestBody);\n    }\n  }\n\n  /**\n   * Tracks if the next message to be sent is the first message of the stream.\n   */\n  private isFirstStreamMessage = true;\n\n  /**\n   * Tracks the last auth token sent to the server.\n   * Used to detect if the token has changed and needs to be resent.\n   */\n  private lastSentAuthToken: string | null = null;\n\n  /**\n   * Indicates whether we should include the auth token in the next message.\n   * Only true if there is an auth token and it is different from the last sent auth token, or this\n   * is the first message.\n   */\n  private get shouldIncludeAuth(): boolean {\n    return (\n      this.isFirstStreamMessage ||\n      (!!this._authToken && this._authToken !== this.lastSentAuthToken)\n    );\n  }\n\n  /**\n   * Called by the concrete transport implementation when the physical connection is ready.\n   */\n  protected onConnectionReady(): void {\n    this.isFirstStreamMessage = true;\n    this.lastSentAuthToken = null;\n    this.hasWaitedForInitialAuth = false;\n  }\n\n  /**\n   * Begin closing the connection. Waits for {@linkcode IDLE_CONNECTION_TIMEOUT_MS} without cleaning up\n   * any requests (meaning it will not close after the timeout unless the requests are closed first).\n   * This is a graceful close - it will be called when there are no more active subscriptions, so\n   * there's no need to cleanup.\n   */\n  private startIdleCloseTimeout(): void {\n    if (this.idleTimeout) {\n      return;\n    }\n    this.idleTimeout = setTimeout(() => {\n      this.idleTimeout = null;\n      // Safety check: Don't close if new requests arrived during the timeout!\n      if (this.hasActiveSubscriptions || this.hasActiveExecuteRequests) {\n        return;\n      }\n      void this.cleanupAndTerminate(\n        Code.OTHER,\n        'Stream closed due to idleness.'\n      );\n    }, IDLE_CONNECTION_TIMEOUT_MS);\n  }\n\n  /**\n   * Cancel closing the connection.\n   */\n  private cancelClose(): void {\n    if (this.idleTimeout) {\n      clearTimeout(this.idleTimeout);\n      this.idleTimeout = null;\n    }\n  }\n\n  /**\n   * Reject all active execute promises and notify all subscribe observers with the given error.\n   * Clear active request tracking maps without cancelling or re-invoking any requests.\n   */\n  private rejectAllRequests(code: Code, reason: string): void {\n    this.activeInvokeQueryRequests.clear();\n    this.activeInvokeMutationRequests.clear();\n    this.activeInvokeSubscribeRequests.clear();\n\n    const error = new DataConnectError(code, reason);\n    for (const [mapKey, { rejectFn }] of this.queuedInvokeQueryRequests) {\n      this.queuedInvokeQueryRequests.delete(mapKey);\n      rejectFn(error);\n    }\n    for (const [requestId, { rejectFn }] of this.executeRequestPromises) {\n      this.executeRequestPromises.delete(requestId);\n      rejectFn(error);\n    }\n    for (const [requestId, { rejectFn }] of this.resumeRequestPromises) {\n      this.resumeRequestPromises.delete(requestId);\n      rejectFn(error);\n    }\n    for (const [requestId, observer] of this.subscribeObservers) {\n      this.subscribeObservers.delete(requestId);\n      observer.onDisconnect(code, reason);\n    }\n    this.pendingCancellations.clear();\n    this.cancelReconnect();\n  }\n\n  /**\n   * Reject all mutation execute promises.\n   * Clear active request tracking maps without cancelling or re-invoking any requests.\n   */\n  private rejectAllMutationsOnReconnect(): void {\n    const error = new DataConnectError(\n      Code.OTHER,\n      'Mutation aborted due to stream disconnect.'\n    );\n    for (const [_, requests] of this.activeInvokeMutationRequests) {\n      for (const request of requests) {\n        const promise = this.executeRequestPromises.get(request.requestId);\n        if (promise) {\n          promise.rejectFn(error);\n          this.executeRequestPromises.delete(request.requestId);\n        }\n      }\n    }\n    this.activeInvokeMutationRequests.clear();\n  }\n\n  /**\n   * Called by concrete implementations when the stream is successfully closed, gracefully or otherwise.\n   */\n  protected onStreamClose(code: number, reason: string): void {\n    this.cancelClose();\n    if (!this.hasActiveSubscriptions) {\n      // skip reconnection if there are no active subscriptions\n      void this.cleanupAndTerminate(\n        Code.OTHER,\n        `Stream disconnected while idle with code ${code}: ${reason}`\n      );\n      return;\n    }\n    logDebug(\n      `Stream disconnected with code ${code}: ${reason}. Attempting reconnect...`\n    );\n    this.rejectAllMutationsOnReconnect();\n    this.startReconnectBackoff();\n  }\n\n  /**\n   * Prepares a stream request message by adding necessary headers and metadata.\n   * If this is the first message on the stream, it includes the resource name, auth token, and App Check token.\n   * If the auth token has refreshed since the last message, it includes the new auth token.\n   *\n   * This method is called by the concrete transport implementation before sending a message.\n   *\n   * @returns the requestBody, with attached headers and initial request fields\n   */\n  protected prepareMessage<\n    Variables,\n    StreamBody extends DataConnectStreamRequest<Variables>\n  >(requestBody: StreamBody): StreamBody {\n    const preparedRequestBody: StreamBody = { ...requestBody };\n    const headers: StreamRequestHeaders = {};\n    if (this.appId) {\n      headers['x-firebase-gmpid'] = this.appId;\n    }\n    headers['X-Goog-Api-Client'] = getGoogApiClientValue(\n      this._isUsingGen,\n      this._callerSdkType\n    );\n    if (this.shouldIncludeAuth && this._authToken) {\n      headers['X-Firebase-Auth-Token'] = this._authToken;\n      this.lastSentAuthToken = this._authToken;\n    }\n    if (this.isFirstStreamMessage) {\n      if (this._appCheckToken) {\n        headers['X-Firebase-App-Check'] = this._appCheckToken;\n      }\n      preparedRequestBody.name = this._connectorResourcePath;\n    }\n    preparedRequestBody.headers = headers;\n    this.isFirstStreamMessage = false;\n    return preparedRequestBody;\n  }\n\n  /**\n   * Sends a request message to the server via the concrete implementation.\n   * Ensures the connection is ready and prepares the message before sending.\n   * @returns A promise that resolves when the request message has been sent.\n   */\n  private async sendRequestMessage<Variables>(\n    requestBody: DataConnectStreamRequest<Variables>\n  ): Promise<void> {\n    if (!this.hasWaitedForInitialAuth && this.authProvider) {\n      await this.getWithAuth();\n      this.hasWaitedForInitialAuth = true;\n    }\n    if (this.streamIsReady) {\n      const prepared = this.prepareMessage(requestBody);\n      return this.sendMessage(prepared);\n    }\n    return this.ensureConnection().then(() => {\n      const prepared = this.prepareMessage(requestBody);\n      return this.sendMessage(prepared);\n    });\n  }\n\n  /**\n   * Helper to generate a consistent string key for the request tracking maps.\n   */\n  private getMapKey(operationName: string, variables?: unknown): string {\n    const sortedVariables = this.sortObjectKeys(variables);\n    return JSON.stringify({ operationName, variables: sortedVariables });\n  }\n\n  /**\n   * Recursively sorts the keys of an object.\n   */\n  private sortObjectKeys(obj: unknown): unknown {\n    if (obj === null || typeof obj !== 'object' || Array.isArray(obj)) {\n      return obj;\n    }\n    const sortedObj: Record<string, unknown> = {};\n    Object.keys(obj as Record<string, unknown>)\n      .sort()\n      .forEach(key => {\n        sortedObj[key] = this.sortObjectKeys(\n          (obj as Record<string, unknown>)[key]\n        );\n      });\n    return sortedObj;\n  }\n\n  /**\n   * @inheritdoc\n   * @remarks\n   * This method synchronously updates the request tracking data structures before sending any message.\n   * If any asynchronous functionality is added to this function, it MUST be done in a way that\n   * preserves the synchronous update of the tracking data structures before the method returns.\n   */\n  invokeQuery<Data, Variables>(\n    queryName: string,\n    variables?: Variables\n  ): Promise<DataConnectResponse<Data>> {\n    const mapKey = this.getMapKey(queryName, variables);\n\n    if (this.activeInvokeQueryRequests.has(mapKey)) {\n      return this.queueInvokeQueryRequest(mapKey);\n    }\n\n    return this.executeOrResumeQuery(queryName, variables, mapKey);\n  }\n\n  /**\n   * Queue a new query execute request to be executed after the currently active query execute\n   * request resolves, and track + return a promise associated with the queued request. If there is\n   * already a queued request for this mapKey, return the existing queued request's promise instead.\n   */\n  private queueInvokeQueryRequest<Data>(\n    mapKey: string\n  ): Promise<DataConnectResponse<Data>> {\n    const existingQueued = this.queuedInvokeQueryRequests.get(mapKey);\n    if (existingQueued) {\n      // only queue one request per mapKey - return existing queued request promise\n      return existingQueued.responsePromise;\n    }\n\n    let resolveFn: (response: DataConnectResponse<Data>) => void;\n    // eslint-disable-next-line @typescript-eslint/no-explicit-any\n    let rejectFn: (reason: any) => void;\n    const responsePromise = new Promise<DataConnectResponse<Data>>(\n      (resolve, reject) => {\n        resolveFn = resolve;\n        rejectFn = reject;\n      }\n    );\n\n    this.queuedInvokeQueryRequests.set(mapKey, {\n      responsePromise,\n      resolveFn: resolveFn!,\n      rejectFn: rejectFn!\n    });\n\n    return responsePromise;\n  }\n\n  /**\n   * Executes or resumes a query. Does not check for any active requests which may be overwritten by\n   * this request - this should be handled by the caller.\n   */\n  private executeOrResumeQuery<Data, Variables>(\n    queryName: string,\n    variables: Variables | undefined,\n    mapKey: string,\n    queuedInvokeOperationPromise?: InvokeOperationPromise<Data>\n  ): Promise<DataConnectResponse<Data>> {\n    const activeSubscription = this.activeInvokeSubscribeRequests.get(mapKey);\n\n    let resolveFn: (response: DataConnectResponse<Data>) => void;\n    // eslint-disable-next-line @typescript-eslint/no-explicit-any\n    let rejectFn: (reason: any) => void;\n    let responsePromise: Promise<DataConnectResponse<Data>>;\n\n    // track the existing queued promise if one exists - otherwise create a new one\n    if (queuedInvokeOperationPromise) {\n      resolveFn = queuedInvokeOperationPromise.resolveFn;\n      rejectFn = queuedInvokeOperationPromise.rejectFn;\n      responsePromise = queuedInvokeOperationPromise.responsePromise;\n    } else {\n      responsePromise = new Promise<DataConnectResponse<Data>>(\n        (resolve, reject) => {\n          resolveFn = resolve;\n          rejectFn = reject;\n        }\n      );\n    }\n\n    let requestId: string;\n    let requestBody: ExecuteStreamRequest<Variables> | ResumeStreamRequest;\n\n    if (activeSubscription) {\n      // resume!\n      requestId = activeSubscription.requestId;\n      requestBody = { requestId, resume: {} };\n      this.resumeRequestPromises.set(requestId, {\n        responsePromise,\n        resolveFn: resolveFn!,\n        rejectFn: rejectFn!\n      });\n    } else {\n      // execute!\n      requestId = this.nextRequestId();\n      requestBody = {\n        requestId,\n        execute: { operationName: queryName, variables }\n      };\n      this.executeRequestPromises.set(requestId, {\n        responsePromise,\n        resolveFn: resolveFn!,\n        rejectFn: rejectFn!\n      });\n    }\n\n    this.activeInvokeQueryRequests.set(mapKey, requestBody);\n\n    responsePromise = responsePromise.finally(() => {\n      this.onInvokeQueryRequestFulfilled(\n        queryName,\n        variables,\n        mapKey,\n        requestId\n      );\n    });\n\n    this.sendRequestMessage(requestBody).catch(err => {\n      rejectFn(err);\n    });\n    return responsePromise;\n  }\n\n  /**\n   * When a query invoke request is fulfilled, clean up and trigger the next queued\n   * request if one exists.\n   */\n  private onInvokeQueryRequestFulfilled(\n    queryName: string,\n    variables: unknown,\n    mapKey: string,\n    requestId: string\n  ): void {\n    this.cleanupInvokeQueryRequest(requestId, mapKey);\n\n    const deferredCancel = this.pendingCancellations.get(requestId);\n    if (deferredCancel) {\n      this.pendingCancellations.delete(requestId);\n      this.cancelSubscription(requestId, mapKey);\n    }\n\n    const queuedRequestPromise = this.queuedInvokeQueryRequests.get(mapKey);\n    if (!queuedRequestPromise) {\n      if (!this.hasActiveSubscriptions && !this.hasActiveExecuteRequests) {\n        this.startIdleCloseTimeout();\n      }\n      return;\n    }\n\n    this.queuedInvokeQueryRequests.delete(mapKey);\n\n    void this.executeOrResumeQuery(\n      queryName,\n      variables,\n      mapKey,\n      queuedRequestPromise\n    );\n  }\n\n  /**\n   * @inheritdoc\n   * @remarks\n   * This method synchronously updates the request tracking data structures before sending any message.\n   * If any asynchronous functionality is added to this function, it MUST be done in a way that\n   * preserves the synchronous update of the tracking data structures before the method returns.\n   */\n  invokeMutation<Data, Variables>(\n    mutationName: string,\n    variables?: Variables\n  ): Promise<DataConnectResponse<Data>> {\n    const requestId = this.nextRequestId();\n    const activeRequestKey = { operationName: mutationName, variables };\n    const mapKey = this.getMapKey(mutationName, variables);\n    const executeBody: ExecuteStreamRequest<Variables> = {\n      requestId,\n      execute: activeRequestKey\n    };\n\n    let { responsePromise, rejectFn } = this.trackInvokeMutationRequest<Data>(\n      requestId,\n      mapKey,\n      executeBody\n    );\n    responsePromise = responsePromise.finally(() => {\n      this.cleanupInvokeMutationRequest(requestId, mapKey);\n      if (!this.hasActiveSubscriptions && !this.hasActiveExecuteRequests) {\n        this.startIdleCloseTimeout();\n      }\n    });\n\n    // asynchronous, fire and forget\n    this.sendRequestMessage<Variables>(executeBody).catch(err => {\n      rejectFn(err);\n    });\n    return responsePromise;\n  }\n\n  /**\n   * @inheritdoc\n   * @remarks\n   * This method synchronously updates the request tracking data structures before sending any message\n   * or cancelling the closing of the stream. If any asynchronous functionality is added to this function,\n   * it MUST be done in a way that preserves the synchronous update of the tracking data structures\n   * before the method returns.\n   */\n  invokeSubscribe<Data, Variables>(\n    observer: SubscribeObserver<Data>,\n    queryName: string,\n    variables: Variables\n  ): void {\n    const mapKey = this.getMapKey(queryName, variables);\n    const existingSubscribe = this.activeInvokeSubscribeRequests.get(mapKey);\n\n    // if this query is pending cancellation, cancel the cancellation!\n    if (existingSubscribe) {\n      const requestId = existingSubscribe.requestId;\n      if (this.pendingCancellations.has(requestId)) {\n        this.pendingCancellations.delete(requestId);\n        this.subscribeObservers.set(requestId, observer);\n      }\n    } else {\n      const requestId = this.nextRequestId();\n      const activeRequestKey = { operationName: queryName, variables };\n      const subscribeBody: SubscribeStreamRequest<Variables> = {\n        requestId,\n        subscribe: activeRequestKey\n      };\n\n      this.trackInvokeSubscribeRequest<Data>(\n        requestId,\n        mapKey,\n        subscribeBody,\n        observer\n      );\n\n      // asynchronous, fire and forget\n      this.sendRequestMessage<Variables>(subscribeBody).catch(err => {\n        observer.onError(err instanceof Error ? err : new Error(String(err)));\n        this.cleanupInvokeSubscribeRequest(requestId, mapKey);\n        if (!this.hasActiveSubscriptions) {\n          this.startIdleCloseTimeout();\n        }\n      });\n    }\n    // if we are waiting to close the stream, cancel closing!\n    this.cancelClose();\n  }\n\n  /**\n   * @inheritdoc\n   * @remarks\n   * This method synchronously updates the request tracking data structures before sending any message.\n   * If any asynchronous functionality is added to this function, it MUST be done in a way that\n   * preserves the synchronous update of the tracking data structures before the method returns.\n   */\n  invokeUnsubscribe<Variables>(queryName: string, variables: Variables): void {\n    const mapKey = this.getMapKey(queryName, variables);\n    const subscribeRequest = this.activeInvokeSubscribeRequests.get(mapKey);\n    if (!subscribeRequest) {\n      return;\n    }\n    const requestId = subscribeRequest.requestId;\n\n    this.subscribeObservers.delete(requestId);\n    const resumePromise = this.resumeRequestPromises.get(requestId);\n    if (resumePromise) {\n      this.pendingCancellations.set(requestId, {\n        operationName: queryName,\n        variables\n      });\n      return;\n    }\n    this.cancelSubscription(requestId, mapKey);\n  }\n\n  /**\n   * Cancels a subscription, cleans up the request tracking data structures, and checks to see if we\n   * should close the stream due to inactivity.\n   */\n  private cancelSubscription(requestId: string, mapKey: string): void {\n    this.cleanupInvokeSubscribeRequest(requestId, mapKey);\n    const cancelBody: CancelStreamRequest = {\n      requestId,\n      cancel: {}\n    };\n\n    // asynchronous, fire and forget\n    this.sendRequestMessage(cancelBody).catch(err => {\n      logError(`Stream Transport failed to send unsubscribe message: ${err}`);\n    });\n\n    if (!this.hasActiveSubscriptions) {\n      this.startIdleCloseTimeout();\n    }\n  }\n\n  onAuthTokenChanged(newToken: string | null): void {\n    const oldAuthToken = this._authToken;\n    this._authToken = newToken;\n\n    const oldAuthUid = this.authUid;\n    const newAuthUid = this.authProvider?.getAuth()?.getUid();\n    this.authUid = newAuthUid;\n\n    // onAuthTokenChanged gets called by the auth provider once it initializes, so we must make sure\n    // we don't prematurely disconnect the stream if this is the initial call.\n    const isInitialAuth = oldAuthUid === undefined;\n    if (isInitialAuth) {\n      return;\n    }\n\n    if (\n      (oldAuthToken && newToken === null) || // user logged out\n      (!oldAuthUid && newAuthUid) || // user logged in\n      (oldAuthUid && newAuthUid !== oldAuthUid) // logged in user changed\n    ) {\n      void this.cleanupAndTerminate(\n        Code.UNAUTHORIZED,\n        'Stream disconnected due to auth change.'\n      );\n    }\n  }\n\n  /**\n   * Handle a response message from the server. Called by the connection-specific implementation after\n   * it's transformed a message from the server into a {@linkcode DataConnectResponse}.\n   * @param requestId the Request ID associated with this response.\n   * @param response the response from the server.\n   */\n  protected async handleResponse<Data>(\n    requestId: string,\n    response: DataConnectResponse<Data>\n  ): Promise<void> {\n    if (this.executeRequestPromises.has(requestId)) {\n      const { resolveFn, rejectFn } =\n        this.executeRequestPromises.get(requestId)!;\n      this.handleInvokeOperationResponse(resolveFn, rejectFn, response);\n    } else if (\n      this.subscribeObservers.has(requestId) ||\n      this.resumeRequestPromises.has(requestId)\n    ) {\n      const observer = this.subscribeObservers.get(requestId);\n      const resumePromise = this.resumeRequestPromises.get(requestId);\n\n      if (resumePromise) {\n        this.resumeRequestPromises.delete(requestId);\n        const { resolveFn, rejectFn } = resumePromise;\n        this.handleInvokeOperationResponse(resolveFn, rejectFn, response);\n      }\n\n      if (observer) {\n        try {\n          await observer.onData(response);\n        } catch (e) {\n          logError(`Error in observer callback: ${e}`);\n        }\n      }\n    } else {\n      logError(\n        `Stream response contained unrecognized requestId '${requestId}'`\n      );\n    }\n  }\n\n  /**\n   * Handles an invoke operation response, resolving or rejecting the promise returned to the user\n   * Does not handle any cleanup for requests - this should be handled by the caller or the promise's\n   * finally() block.\n   */\n  private handleInvokeOperationResponse<Data>(\n    resolveFn: (value: DataConnectResponse<Data>) => void,\n    rejectFn: (reason: unknown) => void,\n    response: DataConnectResponse<Data>\n  ): void {\n    if (response.errors && response.errors.length) {\n      const failureResponse: DataConnectOperationFailureResponse = {\n        errors: response.errors as [],\n        data: response.data as Record<string, unknown>\n      };\n      const stringified = JSON.stringify(response.errors);\n      rejectFn(\n        new DataConnectOperationError(\n          'DataConnect error while performing request: ' + stringified,\n          failureResponse\n        )\n      );\n    } else {\n      resolveFn(response);\n    }\n  }\n}\n","/**\n * @license\n * Copyright 2026 Google LLC\n *\n * Licensed under the Apache License, Version 2.0 (the \"License\");\n * you may not use this file except in compliance with the License.\n * You may obtain a copy of the License at\n *\n * http://www.apache.org/licenses/LICENSE-2.0\n *\n * Unless required by applicable law or agreed to in writing, software\n * distributed under the License is distributed on an \"AS IS\" BASIS,\n * WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\n * See the License for the specific language governing permissions and\n * limitations under the License.\n */\n\nimport { Code, DataConnectError } from '../../core/error';\nimport { logError } from '../../logger';\nimport { websocketUrlBuilder } from '../../util/url';\nimport { DataConnectResponse } from '../transport';\n\nimport { AbstractDataConnectStreamTransport } from './streamTransport';\nimport { DataConnectStreamRequest, DataConnectStreamResponse } from './wire';\n\n/** The WebSocket implementation to be used by the {@link WebSocketTransport}. */\nlet connectWebSocket: typeof WebSocket | null = globalThis.WebSocket;\n\n/**\n * This function is ONLY used for testing and for ensuring compatability in environments which may\n * be using a poyfill and/or bundlers. It should not be called by users of the Firebase JS SDK.\n * @internal\n */\nexport function initializeWebSocket(webSocketImpl: typeof WebSocket): void {\n  connectWebSocket = webSocketImpl;\n}\n\n/**\n * The code used to close the WebSocket connection.\n * This is a protocol-level code, and is not the same as the {@link Code | DataConnect error code}.\n * @internal\n */\nexport const WEBSOCKET_CLOSE_CODE = 1000;\n\n/**\n * An {@link AbstractDataConnectStreamTransport | Stream Transport} implementation that uses {@link WebSocket | WebSockets} to stream requests and responses.\n * This class handles the lifecycle of the WebSocket connection, including automatic\n * reconnection and request correlation.\n * @internal\n */\nexport class WebSocketTransport extends AbstractDataConnectStreamTransport {\n  get endpointUrl(): string {\n    return websocketUrlBuilder(\n      {\n        connector: this._connectorName,\n        location: this._location,\n        projectId: this._project,\n        service: this._serviceName\n      },\n      {\n        host: this._host,\n        sslEnabled: this._secure,\n        port: this._port\n      }\n    );\n  }\n\n  /** Decodes binary WebSocket responses to strings */\n  private decoder: TextDecoder | undefined = undefined;\n\n  /**\n   * Decodes a WebSocket response from a Uint8Array to a JSON object.\n   * Emulator does not send messages as Uint8Arrays, but prod does.\n   */\n  private decodeBinaryResponse(data: ArrayBuffer): string {\n    if (!this.decoder) {\n      this.decoder = new TextDecoder('utf-8');\n    }\n    return this.decoder.decode(data);\n  }\n\n  /** The current connection to the server. Undefined if disconnected. */\n  private connection: WebSocket | undefined = undefined;\n\n  get streamIsReady(): boolean {\n    return this.connection?.readyState === WebSocket.OPEN;\n  }\n\n  /**\n   * Current connection attempt. If null, we are not currently attemping to connect (not connected,\n   * or already connected). Will be resolved or rejected when the connection is opened or fails to open.\n   */\n  private connectionAttempt: Promise<void> | null = null;\n\n  protected ensureConnection(): Promise<void> {\n    try {\n      if (this.streamIsReady) {\n        return Promise.resolve();\n      }\n      if (this.connectionAttempt) {\n        return this.connectionAttempt;\n      }\n      this.connectionAttempt = new Promise<void>((resolve, reject) => {\n        if (!connectWebSocket) {\n          throw new DataConnectError(\n            Code.OTHER,\n            'No WebSocket Implementation detected!'\n          );\n        }\n        const ws = new connectWebSocket(this.endpointUrl);\n        this.connection = ws;\n        this.connection!.binaryType = 'arraybuffer';\n\n        ws.onopen = () => {\n          this.isUnableToConnect = false;\n          this.onConnectionReady();\n          resolve();\n        };\n\n        ws.onerror = event => {\n          this.connectionAttempt = null;\n          this.isUnableToConnect = true;\n          const error = new DataConnectError(\n            Code.OTHER,\n            `Error using WebSocket connection, closing WebSocket`\n          );\n          this.handleError(error);\n          reject(error);\n        };\n\n        ws.onmessage = ev =>\n          this.handleWebSocketMessage(ev).catch(async reason => {\n            this.handleError(reason);\n          });\n\n        ws.onclose = ev => this.handleWebsocketDisconnect(ev);\n      });\n\n      return this.connectionAttempt;\n    } catch (error) {\n      this.handleError(error);\n      throw error;\n    }\n  }\n\n  protected openConnection(): Promise<void> {\n    return this.ensureConnection().catch(err => {\n      throw new DataConnectError(\n        Code.OTHER,\n        `Failed to open connection: ${err}`\n      );\n    });\n  }\n\n  protected closeConnection(code?: number, reason?: string): Promise<void> {\n    if (!this.connection) {\n      this.connectionAttempt = null;\n      return Promise.resolve();\n    }\n    let error;\n    try {\n      if (reason) {\n        // reason string can be max 123 bytes (not characters, bytes)\n        // https://developer.mozilla.org/en-US/docs/Web/API/WebSocketStream/close#parameters\n        const MAX_BYTES = 123;\n        const encoder = new TextEncoder();\n        const bytes = encoder.encode(reason);\n        if (bytes.length <= MAX_BYTES) {\n          this.connection.close(code, reason);\n        } else {\n          const buf = new Uint8Array(MAX_BYTES);\n          const { read } = encoder.encodeInto(reason, buf);\n          const truncatedReason = reason.substring(0, read);\n          this.connection.close(code, truncatedReason);\n        }\n      } else {\n        this.connection.close(code);\n      }\n    } catch (e) {\n      error = e;\n    } finally {\n      this.connection = undefined;\n      this.connectionAttempt = null;\n    }\n    if (error) {\n      return Promise.reject(error);\n    }\n    return Promise.resolve();\n  }\n\n  /**\n   * Handle a disconnection from the server. Initiates graceful clean up and reconnection attempts.\n   * @param ev the {@link CloseEvent} that closed the WebSocket.\n   */\n  private handleWebsocketDisconnect(ev: CloseEvent): void {\n    this.connection = undefined;\n    this.connectionAttempt = null;\n    this.onStreamClose(ev.code, ev.reason);\n  }\n\n  /**\n   * Handle an error that occurred on the WebSocket. Close the connection and reject all active requests.\n   */\n  private handleError(error?: unknown): void {\n    logError(`DataConnect WebSocket error, closing stream: ${error}`);\n    let reason = error ? String(error) : 'Unknown Error';\n    if (error instanceof DataConnectError) {\n      reason = error.message;\n    }\n    void this.closeConnection(WEBSOCKET_CLOSE_CODE, reason);\n  }\n\n  protected sendMessage<Variables>(\n    requestBody: DataConnectStreamRequest<Variables>\n  ): Promise<void> {\n    return this.ensureConnection().then(() => {\n      try {\n        this.connection!.send(JSON.stringify(requestBody));\n        return Promise.resolve();\n      } catch (err) {\n        this.handleError(err);\n        throw new DataConnectError(\n          Code.OTHER,\n          `Failed to send message: ${String(err)}`\n        );\n      }\n    });\n  }\n\n  /**\n   * Handles incoming WebSocket messages.\n   * @param ev The {@link MessageEvent} from the WebSocket.\n   */\n  private async handleWebSocketMessage(ev: MessageEvent): Promise<void> {\n    const result: DataConnectStreamResponse<unknown> = this.parseWebSocketData(\n      ev.data\n    );\n    const requestId = result.requestId;\n\n    const response: DataConnectResponse<unknown> = {\n      data: result.data,\n      errors: result.errors,\n      extensions: result.extensions || { dataConnect: [] }\n    };\n\n    await this.handleResponse(requestId, response);\n  }\n\n  /**\n   * Parse a response from the server. Assert that it has a {@link DataConnectStreamResponse.requestId | requestId}.\n   * @param data the message from the server to be parsed\n   * @returns the parsed message as a {@link DataConnectStreamResponse}\n   * @throws {DataConnectError} if parsing fails or message is malformed.\n   */\n  private parseWebSocketData<Data>(\n    // eslint-disable-next-line @typescript-eslint/no-explicit-any\n    data: any\n  ): DataConnectStreamResponse<Data> {\n    const dataIsString = typeof data === 'string';\n    /** raw websocket message */\n    let webSocketMessage;\n    /** object containing data, errors, and extensions */\n    let result;\n    try {\n      if (dataIsString) {\n        webSocketMessage = JSON.parse(data);\n      } else {\n        webSocketMessage = JSON.parse(this.decodeBinaryResponse(data));\n      }\n    } catch (err) {\n      throw new DataConnectError(\n        Code.OTHER,\n        `Could not parse WebSocket message: ${\n          err instanceof Error ? err.message : String(err)\n        }`\n      );\n    }\n    if (typeof webSocketMessage !== 'object' || webSocketMessage === null) {\n      throw new DataConnectError(\n        Code.OTHER,\n        'WebSocket message is not an object'\n      );\n    }\n    if (dataIsString) {\n      if (!('result' in webSocketMessage)) {\n        throw new DataConnectError(\n          Code.OTHER,\n          'WebSocket message from emulator did not include result'\n        );\n      }\n      if (\n        typeof webSocketMessage.result !== 'object' ||\n        webSocketMessage.result === null\n      ) {\n        throw new DataConnectError(\n          Code.OTHER,\n          'WebSocket message result is not an object'\n        );\n      }\n      result = webSocketMessage.result;\n    } else {\n      result = webSocketMessage;\n    }\n    if (!('requestId' in result)) {\n      throw new DataConnectError(\n        Code.OTHER,\n        'WebSocket message did not include requestId'\n      );\n    }\n    return result;\n  }\n}\n","/**\n * @license\n * Copyright 2025 Google LLC\n *\n * Licensed under the Apache License, Version 2.0 (the \"License\");\n * you may not use this file except in compliance with the License.\n * You may obtain a copy of the License at\n *\n *   http://www.apache.org/licenses/LICENSE-2.0\n *\n * Unless required by applicable law or agreed to in writing, software\n * distributed under the License is distributed on an \"AS IS\" BASIS,\n * WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\n * See the License for the specific language governing permissions and\n * limitations under the License.\n */\n\nexport type FDCScalarValue =\n  | string\n  | number\n  | boolean\n  | undefined\n  | null\n  | Record<string, unknown>\n  | FDCScalarValue[];\n\nexport interface EntityDataObjectJson {\n  map: {\n    [key: string]: FDCScalarValue;\n  };\n  referencedFrom: string[];\n  globalID: string;\n}\n\nexport class EntityDataObject {\n  getServerValue(key: string): unknown {\n    return this.serverValues[key];\n  }\n  private serverValues: { [key: string]: FDCScalarValue } = {};\n  private referencedFrom = new Set<string>();\n  constructor(public readonly globalID: string) {}\n  getServerValues(): { [key: string]: FDCScalarValue } {\n    return this.serverValues;\n  }\n  toJSON(): EntityDataObjectJson {\n    return {\n      globalID: this.globalID,\n      map: this.serverValues,\n      referencedFrom: Array.from(this.referencedFrom)\n    };\n  }\n  static fromJSON(json: EntityDataObjectJson): EntityDataObject {\n    const edo = new EntityDataObject(json.globalID);\n    edo.serverValues = json.map;\n    edo.referencedFrom = new Set(json.referencedFrom);\n    return edo;\n  }\n\n  updateServerValue(\n    key: string,\n    value: FDCScalarValue,\n    requestedFrom: string\n  ): string[] {\n    this.serverValues[key] = value;\n    this.referencedFrom.add(requestedFrom);\n    return Array.from(this.referencedFrom);\n  }\n}\n","/**\n * @license\n * Copyright 2025 Google LLC\n *\n * Licensed under the Apache License, Version 2.0 (the \"License\");\n * you may not use this file except in compliance with the License.\n * You may obtain a copy of the License at\n *\n *   http://www.apache.org/licenses/LICENSE-2.0\n *\n * Unless required by applicable law or agreed to in writing, software\n * distributed under the License is distributed on an \"AS IS\" BASIS,\n * WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\n * See the License for the specific language governing permissions and\n * limitations under the License.\n */\n\nimport { InternalCacheProvider } from './CacheProvider';\nimport { EntityDataObject } from './EntityDataObject';\nimport { ResultTree } from './ResultTree';\n\nexport class InMemoryCacheProvider implements InternalCacheProvider {\n  private edos = new Map<string, EntityDataObject>();\n  private resultTrees = new Map<string, ResultTree>();\n  constructor(private _keyId: string) {}\n\n  async setResultTree(queryId: string, rt: ResultTree): Promise<void> {\n    this.resultTrees.set(queryId, rt);\n  }\n  async getResultTree(queryId: string): Promise<ResultTree | undefined> {\n    return this.resultTrees.get(queryId);\n  }\n  async updateEntityData(entityData: EntityDataObject): Promise<void> {\n    this.edos.set(entityData.globalID, entityData);\n  }\n  async getEntityData(globalId: string): Promise<EntityDataObject> {\n    if (!this.edos.has(globalId)) {\n      this.edos.set(globalId, new EntityDataObject(globalId));\n    }\n    // Because of the above, we can guarantee that there will be an EDO at the globalId.\n    return this.edos.get(globalId)!;\n  }\n  close(): Promise<void> {\n    // No-op\n    return Promise.resolve();\n  }\n}\n","/**\n * @license\n * Copyright 2025 Google LLC\n *\n * Licensed under the Apache License, Version 2.0 (the \"License\");\n * you may not use this file except in compliance with the License.\n * You may obtain a copy of the License at\n *\n *   http://www.apache.org/licenses/LICENSE-2.0\n *\n * Unless required by applicable law or agreed to in writing, software\n * distributed under the License is distributed on an \"AS IS\" BASIS,\n * WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\n * See the License for the specific language governing permissions and\n * limitations under the License.\n */\n\nimport { Code, DataConnectError } from '../core/error';\n\nimport { InternalCacheProvider } from './CacheProvider';\nimport {\n  EntityDataObject,\n  EntityDataObjectJson,\n  FDCScalarValue\n} from './EntityDataObject';\nimport { ImpactedQueryRefsAccumulator } from './ImpactedQueryRefsAccumulator';\n\nexport const GLOBAL_ID_KEY = '_id';\nexport const OBJECT_LISTS_KEY = '_objectLists';\nexport const REFERENCES_KEY = '_references';\nexport const SCALARS_KEY = '_scalars';\nexport const ENTITY_DATA_KEYS_KEY = '_entity_data_keys';\nexport class EntityNode {\n  entityData?: EntityDataObject;\n  scalars: Record<string, FDCScalarValue> = {};\n  references: { [key: string]: EntityNode } = {};\n  objectLists: {\n    [key: string]: EntityNode[];\n  } = {};\n  globalId?: string;\n  entityDataKeys: Set<string> = new Set();\n\n  async loadData(\n    queryId: string,\n    values: FDCScalarValue,\n    entityIds: Record<string, unknown> | undefined,\n    acc: ImpactedQueryRefsAccumulator,\n    cacheProvider: InternalCacheProvider\n  ): Promise<void> {\n    if (values === undefined) {\n      return;\n    }\n    if (typeof values !== 'object' || Array.isArray(values)) {\n      throw new DataConnectError(\n        Code.INVALID_ARGUMENT,\n        'EntityNode initialized with non-object value'\n      );\n    }\n    if (values === null) {\n      return;\n    }\n\n    if (\n      typeof values === 'object' &&\n      entityIds &&\n      entityIds[GLOBAL_ID_KEY] &&\n      typeof entityIds[GLOBAL_ID_KEY] === 'string'\n    ) {\n      this.globalId = entityIds[GLOBAL_ID_KEY];\n      this.entityData = await cacheProvider.getEntityData(this.globalId);\n    }\n    for (const key in values) {\n      if (values.hasOwnProperty(key)) {\n        if (typeof values[key] === 'object') {\n          if (Array.isArray(values[key])) {\n            const ids: Record<string, unknown> | undefined =\n              entityIds && (entityIds[key] as Record<string, unknown>);\n            const objArray: EntityNode[] = [];\n            const scalarArray: Array<NonNullable<FDCScalarValue>> = [];\n            for (const [index, value] of values[key].entries()) {\n              if (typeof value === 'object') {\n                if (Array.isArray(value)) {\n                  // Note: we don't support sparse arrays.\n                } else {\n                  const entityNode = new EntityNode();\n                  await entityNode.loadData(\n                    queryId,\n                    value,\n                    ids && (ids[index] as Record<string, unknown>),\n                    acc,\n                    cacheProvider\n                  );\n                  objArray.push(entityNode);\n                }\n              } else {\n                scalarArray.push(value);\n              }\n            }\n            if (scalarArray.length > 0 && objArray.length > 0) {\n              this.scalars[key] = values[key];\n            } else if (scalarArray.length > 0) {\n              if (this.entityData) {\n                const impactedRefs = this.entityData.updateServerValue(\n                  key,\n                  scalarArray,\n                  queryId\n                );\n                this.entityDataKeys.add(key);\n                acc.add(impactedRefs);\n              } else {\n                this.scalars[key] = scalarArray;\n              }\n            } else if (objArray.length > 0) {\n              this.objectLists[key] = objArray;\n            } else {\n              this.scalars[key] = [];\n            }\n          } else {\n            if (values[key] === null) {\n              this.scalars[key] = null;\n              continue;\n            }\n            const entityNode = new EntityNode();\n            // TODO: Load Data might need to be pushed into ResultTreeProcessor instead.\n            await entityNode.loadData(\n              queryId,\n              (values as Record<string, FDCScalarValue>)[key],\n              entityIds && (entityIds[key] as Record<string, unknown>),\n              acc,\n              cacheProvider\n            );\n            this.references[key] = entityNode;\n          }\n        } else {\n          if (this.entityData) {\n            const impactedRefs = this.entityData.updateServerValue(\n              key,\n              values[key] as FDCScalarValue,\n              queryId\n            );\n            this.entityDataKeys.add(key);\n            acc.add(impactedRefs);\n          } else {\n            this.scalars[key] = values[key] as FDCScalarValue;\n          }\n        }\n      }\n    }\n    if (this.entityData) {\n      await cacheProvider.updateEntityData(this.entityData);\n    }\n  }\n\n  toJSON(mode: EncodingMode): Record<string, unknown> {\n    const resultObject: Record<string, unknown> = {};\n    if (mode === EncodingMode.hydrated) {\n      if (this.entityData) {\n        for (const key of this.entityDataKeys) {\n          resultObject[key] = this.entityData.getServerValue(key);\n        }\n      }\n\n      if (this.scalars) {\n        Object.assign(resultObject, this.scalars);\n      }\n      if (this.references) {\n        for (const key in this.references) {\n          if (this.references.hasOwnProperty(key)) {\n            resultObject[key] = this.references[key].toJSON(mode);\n          }\n        }\n      }\n      if (this.objectLists) {\n        for (const key in this.objectLists) {\n          if (this.objectLists.hasOwnProperty(key)) {\n            resultObject[key] = this.objectLists[key].map(obj =>\n              obj.toJSON(mode)\n            );\n          }\n        }\n      }\n      return resultObject;\n    } else {\n      // Get JSON representation of dehydrated list\n      if (this.entityData) {\n        resultObject[GLOBAL_ID_KEY] = this.entityData.globalID;\n      }\n\n      resultObject[ENTITY_DATA_KEYS_KEY] = Array.from(this.entityDataKeys);\n\n      if (this.scalars) {\n        resultObject[SCALARS_KEY] = this.scalars;\n      }\n\n      if (this.references) {\n        const references = {} as Record<string, unknown>;\n        for (const key in this.references) {\n          if (this.references.hasOwnProperty(key)) {\n            references[key] = this.references[key].toJSON(mode);\n          }\n        }\n        resultObject[REFERENCES_KEY] = references;\n      }\n      if (this.objectLists) {\n        const objectLists = {} as Record<string, unknown>;\n        for (const key in this.objectLists) {\n          if (this.objectLists.hasOwnProperty(key)) {\n            objectLists[key] = this.objectLists[key].map(obj =>\n              obj.toJSON(mode)\n            );\n          }\n        }\n        resultObject[OBJECT_LISTS_KEY] = objectLists;\n      }\n    }\n\n    return resultObject;\n  }\n\n  static fromJson(obj: DehydratedStubDataObject): EntityNode {\n    const sdo = new EntityNode();\n    if (obj.backingData) {\n      sdo.entityData = EntityDataObject.fromJSON(obj.backingData);\n    }\n    sdo.globalId = obj.globalID;\n    sdo.scalars = obj.scalars;\n    if (obj.references) {\n      const references: Record<string, unknown> = {};\n      for (const key in obj.references) {\n        if (obj.references.hasOwnProperty(key)) {\n          references[key] = EntityNode.fromJson(obj.references[key]);\n        }\n      }\n      sdo.references = references as typeof sdo.references;\n    }\n    if (obj.objectLists) {\n      const objectLists: Record<string, unknown> = {};\n      for (const key in obj.objectLists) {\n        if (obj.objectLists.hasOwnProperty(key)) {\n          objectLists[key] = obj.objectLists[key].map(obj =>\n            EntityNode.fromJson(obj)\n          );\n        }\n      }\n      sdo.objectLists = objectLists as typeof sdo.objectLists;\n    }\n    return sdo;\n  }\n}\n\nexport interface DehydratedStubDataObject {\n  backingData?: EntityDataObjectJson;\n  globalID?: string;\n  scalars: { [key: string]: FDCScalarValue };\n  references: { [key: string]: DehydratedStubDataObject };\n  objectLists: {\n    [key: string]: DehydratedStubDataObject[];\n  };\n}\n\n// Helpful for storing in persistent cache, which is not available yet.\nexport enum EncodingMode {\n  hydrated,\n  dehydrated\n}\n","/**\n * @license\n * Copyright 2025 Google LLC\n *\n * Licensed under the Apache License, Version 2.0 (the \"License\");\n * you may not use this file except in compliance with the License.\n * You may obtain a copy of the License at\n *\n *   http://www.apache.org/licenses/LICENSE-2.0\n *\n * Unless required by applicable law or agreed to in writing, software\n * distributed under the License is distributed on an \"AS IS\" BASIS,\n * WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\n * See the License for the specific language governing permissions and\n * limitations under the License.\n */\n\nimport { EntityNode, DehydratedStubDataObject } from './EntityNode';\n\nexport class ResultTree {\n  /**\n   * Create a {@link ResultTree} from a dehydrated JSON object.\n   * @param value The dehydrated JSON object.\n   * @returns The {@link ResultTree}.\n   */\n  static fromJson(value: DehydratedResultTreeJson): ResultTree {\n    return new ResultTree(\n      EntityNode.fromJson(value.rootStub),\n      value.maxAge,\n      value.cachedAt,\n      value.lastAccessed\n    );\n  }\n  constructor(\n    private rootStub: EntityNode,\n    private maxAge: number = 0,\n    public readonly cachedAt: Date,\n    private _lastAccessed: Date\n  ) {}\n  isStale(): boolean {\n    return (\n      Date.now() - new Date(this.cachedAt.getTime()).getTime() >\n      this.maxAge * 1000\n    );\n  }\n  updateMaxAge(maxAgeInSeconds: number): void {\n    this.maxAge = maxAgeInSeconds;\n  }\n  updateAccessed(): void {\n    this._lastAccessed = new Date();\n  }\n  get lastAccessed(): Date {\n    return this._lastAccessed;\n  }\n  getRootStub(): EntityNode {\n    return this.rootStub;\n  }\n}\n\ninterface DehydratedResultTreeJson {\n  rootStub: DehydratedStubDataObject;\n  maxAge: number;\n  cachedAt: Date;\n  lastAccessed: Date;\n}\n","/**\n * @license\n * Copyright 2025 Google LLC\n *\n * Licensed under the Apache License, Version 2.0 (the \"License\");\n * you may not use this file except in compliance with the License.\n * You may obtain a copy of the License at\n *\n *   http://www.apache.org/licenses/LICENSE-2.0\n *\n * Unless required by applicable law or agreed to in writing, software\n * distributed under the License is distributed on an \"AS IS\" BASIS,\n * WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\n * See the License for the specific language governing permissions and\n * limitations under the License.\n */\n\nexport class ImpactedQueryRefsAccumulator {\n  impacted = new Set<string>();\n  constructor(private queryId: string) {}\n  add(impacted: string[]): void {\n    impacted\n      .filter(ref => ref !== this.queryId)\n      .forEach(ref => this.impacted.add(ref));\n  }\n  consumeEvents(): string[] {\n    const events = Array.from(this.impacted);\n    this.impacted.clear();\n    return events;\n  }\n}\n","/**\n * @license\n * Copyright 2025 Google LLC\n *\n * Licensed under the Apache License, Version 2.0 (the \"License\");\n * you may not use this file except in compliance with the License.\n * You may obtain a copy of the License at\n *\n *   http://www.apache.org/licenses/LICENSE-2.0\n *\n * Unless required by applicable law or agreed to in writing, software\n * distributed under the License is distributed on an \"AS IS\" BASIS,\n * WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\n * See the License for the specific language governing permissions and\n * limitations under the License.\n */\n\nimport { InternalCacheProvider } from './CacheProvider';\nimport { EncodingMode, EntityNode } from './EntityNode';\nimport { ImpactedQueryRefsAccumulator } from './ImpactedQueryRefsAccumulator';\n\ninterface DehydratedResults {\n  entityNode: EntityNode;\n  impacted: string[];\n}\n\nexport class ResultTreeProcessor {\n  /**\n   * Hydrate the EntityNode into a JSON object so that it can be returned to the user.\n   * @param rootStubObject\n   * @returns {string}\n   */\n  hydrateResults(rootStubObject: EntityNode): Record<string, unknown> {\n    return rootStubObject.toJSON(EncodingMode.hydrated);\n  }\n  /**\n   * Dehydrate results so that they can be stored in the cache.\n   * @param json\n   * @param entityIds\n   * @param cacheProvider\n   * @param queryId\n   * @returns {Promise<DehydratedResults>}\n   */\n  async dehydrateResults(\n    json: Record<string, unknown>,\n    entityIds: Record<string, unknown>,\n    cacheProvider: InternalCacheProvider,\n    queryId: string\n  ): Promise<DehydratedResults> {\n    const acc = new ImpactedQueryRefsAccumulator(queryId);\n    const entityNode = new EntityNode();\n    await entityNode.loadData(queryId, json, entityIds, acc, cacheProvider);\n    return {\n      entityNode,\n      impacted: acc.consumeEvents()\n    };\n  }\n}\n","/**\n * @license\n * Copyright 2025 Google LLC\n *\n * Licensed under the Apache License, Version 2.0 (the \"License\");\n * you may not use this file except in compliance with the License.\n * You may obtain a copy of the License at\n *\n *   http://www.apache.org/licenses/LICENSE-2.0\n *\n * Unless required by applicable law or agreed to in writing, software\n * distributed under the License is distributed on an \"AS IS\" BASIS,\n * WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\n * See the License for the specific language governing permissions and\n * limitations under the License.\n */\n\nimport { generateSHA256Hash } from '@firebase/util';\n\nimport {\n  CacheProvider,\n  CacheSettings,\n  type ConnectorConfig\n} from '../api/DataConnect';\nimport { Code, DataConnectError } from '../core/error';\nimport { type AuthTokenProvider } from '../core/FirebaseAuthProvider';\n\nimport { InternalCacheProvider } from './CacheProvider';\nimport { InMemoryCacheProvider } from './InMemoryCacheProvider';\nimport { ResultTree } from './ResultTree';\nimport { ResultTreeProcessor } from './ResultTreeProcessor';\n\nexport const Memory = 'memory';\n\nexport type DataConnectStorage = typeof Memory;\n\n/**\n * ServerValues\n */\nexport interface ServerValues extends Record<string, unknown> {\n  maxAge?: number;\n}\n\nexport class DataConnectCache {\n  private cacheProvider: InternalCacheProvider | null = null;\n  private uid: string | null = null;\n  constructor(\n    private authProvider: AuthTokenProvider,\n    private projectId: string,\n    private connectorConfig: ConnectorConfig,\n    private host: string,\n    public cacheSettings: CacheSettings\n  ) {\n    this.authProvider.addTokenChangeListener(async _ => {\n      const newUid = this.authProvider.getAuth().getUid();\n      // We should only close if the token changes and so does the new UID\n      if (this.uid !== newUid) {\n        this.cacheProvider?.close();\n        this.uid = newUid;\n        const identifier = await this.getIdentifier(this.uid);\n        this.cacheProvider = this.initializeNewProviders(identifier);\n      }\n    });\n  }\n\n  async initialize(): Promise<void> {\n    if (!this.cacheProvider) {\n      const identifier = await this.getIdentifier(this.uid);\n      this.cacheProvider = this.initializeNewProviders(identifier);\n    }\n  }\n\n  async getIdentifier(uid: string | null): Promise<string> {\n    const identifier = `${\n      'memory' // TODO: replace this with indexeddb when persistence is available.\n    }-${this.projectId}-${this.connectorConfig.service}-${\n      this.connectorConfig.connector\n    }-${this.connectorConfig.location}-${uid}-${this.host}`;\n    const sha256 = await generateSHA256Hash(identifier);\n    return sha256;\n  }\n\n  initializeNewProviders(identifier: string): InternalCacheProvider {\n    return this.cacheSettings.cacheProvider.initialize(identifier);\n  }\n\n  async containsResultTree(queryId: string): Promise<boolean> {\n    await this.initialize();\n    const resultTree = await this.cacheProvider!.getResultTree(queryId);\n    return resultTree !== undefined;\n  }\n  async getResultTree(queryId: string): Promise<ResultTree | undefined> {\n    await this.initialize();\n    return this.cacheProvider!.getResultTree(queryId);\n  }\n  async getResultJSON(queryId: string): Promise<Record<string, unknown>> {\n    await this.initialize();\n    const processor = new ResultTreeProcessor();\n    const cacheProvider = this.cacheProvider;\n    const resultTree = await cacheProvider!.getResultTree(queryId);\n    if (!resultTree) {\n      throw new DataConnectError(\n        Code.INVALID_ARGUMENT,\n        `${queryId} not found in cache. Call \"update()\" first.`\n      );\n    }\n    return processor.hydrateResults(resultTree.getRootStub());\n  }\n  async update(\n    queryId: string,\n    serverValues: ServerValues,\n    entityIds: Record<string, unknown>\n  ): Promise<string[]> {\n    await this.initialize();\n    const processor = new ResultTreeProcessor();\n    const cacheProvider = this.cacheProvider;\n    const { entityNode: stubDataObject, impacted } =\n      await processor.dehydrateResults(\n        serverValues,\n        entityIds,\n        cacheProvider!,\n        queryId\n      );\n    const now = new Date();\n    await cacheProvider!.setResultTree(\n      queryId,\n      new ResultTree(\n        stubDataObject,\n        serverValues.maxAge || this.cacheSettings.maxAgeSeconds,\n        now,\n        now\n      )\n    );\n    return impacted;\n  }\n}\n\nexport class MemoryStub implements CacheProvider<'MEMORY'> {\n  type: 'MEMORY' = 'MEMORY';\n  /**\n   * @internal\n   */\n  initialize(cacheId: string): InMemoryCacheProvider {\n    return new InMemoryCacheProvider(cacheId);\n  }\n}\n","/**\n * @license\n * Copyright 2024 Google LLC\n *\n * Licensed under the Apache License, Version 2.0 (the \"License\");\n * you may not use this file except in compliance with the License.\n * You may obtain a copy of the License at\n *\n *   http://www.apache.org/licenses/LICENSE-2.0\n *\n * Unless required by applicable law or agreed to in writing, software\n * distributed under the License is distributed on an \"AS IS\" BASIS,\n * WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\n * See the License for the specific language governing permissions and\n * limitations under the License.\n */\n\nimport { FirebaseApp, _isFirebaseServerApp } from '@firebase/app';\nimport {\n  AppCheckInternalComponentName,\n  AppCheckTokenListener,\n  AppCheckTokenResult,\n  FirebaseAppCheckInternal\n} from '@firebase/app-check-interop-types';\nimport { Provider } from '@firebase/component';\n\n/**\n * @internal\n * Abstraction around AppCheck's token fetching capabilities.\n */\nexport class AppCheckTokenProvider {\n  private appCheck?: FirebaseAppCheckInternal | null;\n  private serverAppAppCheckToken?: string;\n  constructor(\n    app: FirebaseApp,\n    private appCheckProvider?: Provider<AppCheckInternalComponentName>\n  ) {\n    if (_isFirebaseServerApp(app) && app.settings.appCheckToken) {\n      this.serverAppAppCheckToken = app.settings.appCheckToken;\n    }\n    this.appCheck = appCheckProvider?.getImmediate({ optional: true });\n    if (!this.appCheck) {\n      void appCheckProvider\n        ?.get()\n        .then(appCheck => (this.appCheck = appCheck))\n        .catch();\n    }\n  }\n\n  getToken(): Promise<AppCheckTokenResult | null> {\n    if (this.serverAppAppCheckToken) {\n      return Promise.resolve({ token: this.serverAppAppCheckToken });\n    }\n\n    if (!this.appCheck) {\n      return new Promise<AppCheckTokenResult | null>((resolve, reject) => {\n        // Support delayed initialization of FirebaseAppCheck. This allows our\n        // customers to initialize the RTDB SDK before initializing Firebase\n        // AppCheck and ensures that all requests are authenticated if a token\n        // becomes available before the timoeout below expires.\n        setTimeout(() => {\n          if (this.appCheck) {\n            this.getToken().then(resolve, reject);\n          } else {\n            resolve(null);\n          }\n        }, 0);\n      });\n    }\n    return this.appCheck.getToken();\n  }\n\n  addTokenChangeListener(listener: AppCheckTokenListener): void {\n    void this.appCheckProvider\n      ?.get()\n      .then(appCheck => appCheck.addTokenListener(listener));\n  }\n}\n","/**\n * @license\n * Copyright 2024 Google LLC\n *\n * Licensed under the Apache License, Version 2.0 (the \"License\");\n * you may not use this file except in compliance with the License.\n * You may obtain a copy of the License at\n *\n *   http://www.apache.org/licenses/LICENSE-2.0\n *\n * Unless required by applicable law or agreed to in writing, software\n * distributed under the License is distributed on an \"AS IS\" BASIS,\n * WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\n * See the License for the specific language governing permissions and\n * limitations under the License.\n */\n\nimport { FirebaseOptions } from '@firebase/app-types';\nimport {\n  FirebaseAuthInternal,\n  FirebaseAuthInternalName,\n  FirebaseAuthTokenData\n} from '@firebase/auth-interop-types';\nimport { Provider } from '@firebase/component';\n\nimport { logDebug, logError } from '../logger';\n\n// @internal\nexport interface AuthTokenProvider {\n  getToken(forceRefresh: boolean): Promise<FirebaseAuthTokenData | null>;\n  addTokenChangeListener(listener: AuthTokenListener): void;\n  getAuth(): FirebaseAuthInternal;\n}\nexport type AuthTokenListener = (token: string | null) => void;\n\n// @internal\nexport class FirebaseAuthProvider implements AuthTokenProvider {\n  private _auth: FirebaseAuthInternal;\n  constructor(\n    private _appName: string,\n    private _options: FirebaseOptions,\n    private _authProvider: Provider<FirebaseAuthInternalName>\n  ) {\n    this._auth = _authProvider.getImmediate({ optional: true })!;\n    if (!this._auth) {\n      _authProvider.onInit(auth => (this._auth = auth));\n    }\n  }\n  getAuth(): FirebaseAuthInternal {\n    return this._auth;\n  }\n  getToken(forceRefresh: boolean): Promise<FirebaseAuthTokenData | null> {\n    if (!this._auth) {\n      return new Promise((resolve, reject) => {\n        setTimeout(() => {\n          if (this._auth) {\n            this.getToken(forceRefresh).then(resolve, reject);\n          } else {\n            resolve(null);\n          }\n        }, 0);\n      });\n    }\n    return this._auth.getToken(forceRefresh).catch(error => {\n      if (error && error.code === 'auth/token-not-initialized') {\n        logDebug(\n          'Got auth/token-not-initialized error.  Treating as null token.'\n        );\n        return null;\n      } else {\n        logError(\n          'Error received when attempting to retrieve token: ' +\n            JSON.stringify(error)\n        );\n        return Promise.reject(error);\n      }\n    });\n  }\n  addTokenChangeListener(listener: AuthTokenListener): void {\n    this._auth?.addAuthTokenListener(listener);\n  }\n  removeTokenChangeListener(listener: (token: string | null) => void): void {\n    this._authProvider\n      .get()\n      .then(auth => auth.removeAuthTokenListener(listener))\n      .catch(err => logError(err));\n  }\n}\n","/**\n * @license\n * Copyright 2024 Google LLC\n *\n * Licensed under the Apache License, Version 2.0 (the \"License\");\n * you may not use this file except in compliance with the License.\n * You may obtain a copy of the License at\n *\n *   http://www.apache.org/licenses/LICENSE-2.0\n *\n * Unless required by applicable law or agreed to in writing, software\n * distributed under the License is distributed on an \"AS IS\" BASIS,\n * WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\n * See the License for the specific language governing permissions and\n * limitations under the License.\n */\n\nimport { Extensions } from '../network';\n\nimport { DataConnect, DataConnectOptions } from './DataConnect';\nexport const QUERY_STR = 'query';\nexport const MUTATION_STR = 'mutation';\nexport type ReferenceType = typeof QUERY_STR | typeof MUTATION_STR;\n\nexport const SOURCE_SERVER = 'SERVER';\nexport const SOURCE_CACHE = 'CACHE';\nexport type DataSource = typeof SOURCE_CACHE | typeof SOURCE_SERVER;\n\nexport interface OpResult<Data> {\n  data: Data;\n  source: DataSource;\n  fetchTime: string;\n  extensions?: Extensions;\n}\n\nexport interface OperationRef<_Data, Variables> {\n  name: string;\n  variables: Variables;\n  refType: ReferenceType;\n  dataConnect: DataConnect;\n}\n\nexport interface DataConnectResult<Data, Variables> extends OpResult<Data> {\n  ref: OperationRef<Data, Variables>;\n  // future metadata\n}\n\n/**\n * Serialized RefInfo as a result of `QueryResult.toJSON().refInfo`\n */\nexport interface RefInfo<Variables> {\n  name: string;\n  variables: Variables;\n  connectorConfig: DataConnectOptions;\n}\n/**\n * Serialized Ref as a result of `QueryResult.toJSON()`\n */\nexport interface SerializedRef<Data, Variables> extends OpResult<Data> {\n  refInfo: RefInfo<Variables>;\n}\n","/**\n * @license\n * Copyright 2026 Google LLC\n *\n * Licensed under the Apache License, Version 2.0 (the \"License\");\n * you may not use this file except in compliance with the License.\n * You may obtain a copy of the License at\n *\n *   http://www.apache.org/licenses/LICENSE-2.0\n *\n * Unless required by applicable law or agreed to in writing, software\n * distributed under the License is distributed on an \"AS IS\" BASIS,\n * WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\n * See the License for the specific language governing permissions and\n * limitations under the License.\n */\n\nimport { OpResult } from '../api/Reference';\nimport { DataConnectExtension } from '../network';\nexport function parseEntityIds<T>(\n  result: OpResult<T>\n): Record<string, unknown> {\n  // Iterate through extensions.dataConnect\n  const dataConnectExtensions = result.extensions?.dataConnect;\n  const dataCopy = Object.assign(result);\n  if (!dataConnectExtensions) {\n    return dataCopy;\n  }\n  const ret: Record<string, unknown> = {};\n  for (const extension of dataConnectExtensions) {\n    const { path } = extension;\n    populatePath(path, ret, extension);\n  }\n  return ret;\n}\n\n// mutates the object to update the path\nexport function populatePath(\n  path: Array<string | number>,\n  toUpdate: Record<string | number, unknown>,\n  extension: DataConnectExtension\n): void {\n  let curObj: Record<string | number, unknown> = toUpdate;\n  for (const slice of path) {\n    if (typeof curObj[slice] !== 'object') {\n      curObj[slice] = {};\n    }\n    curObj = curObj[slice] as Record<string, unknown>;\n  }\n\n  if ('entityId' in extension && extension.entityId) {\n    curObj['_id'] = extension.entityId;\n  } else if ('entityIds' in extension) {\n    const entityArr = extension.entityIds;\n    for (let i = 0; i < entityArr.length; i++) {\n      const entityId = entityArr[i];\n      if (typeof curObj[i] === 'undefined') {\n        curObj[i] = {};\n      }\n      (curObj[i] as Record<string, unknown>)._id = entityId;\n    }\n  }\n}\n","/**\n * @license\n * Copyright 2024 Google LLC\n *\n * Licensed under the Apache License, Version 2.0 (the \"License\");\n * you may not use this file except in compliance with the License.\n * You may obtain a copy of the License at\n *\n *   http://www.apache.org/licenses/LICENSE-2.0\n *\n * Unless required by applicable law or agreed to in writing, software\n * distributed under the License is distributed on an \"AS IS\" BASIS,\n * WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\n * See the License for the specific language governing permissions and\n * limitations under the License.\n */\n\nexport type HmacImpl = (obj: Record<string, unknown>) => string;\nexport let encoderImpl: HmacImpl;\nexport type DecodeHmacImpl = (s: string) => Record<string, unknown>;\nexport let decoderImpl: DecodeHmacImpl;\nexport function setEncoder(encoder: HmacImpl): void {\n  encoderImpl = encoder;\n}\nexport function setDecoder(decoder: DecodeHmacImpl): void {\n  decoderImpl = decoder;\n}\nfunction sortKeysForObj(o: Record<string, unknown>): Record<string, unknown> {\n  return Object.keys(o)\n    .sort()\n    .reduce((accumulator, currentKey) => {\n      accumulator[currentKey] = o[currentKey];\n      return accumulator;\n    }, {} as Record<string, unknown>);\n}\nsetEncoder((o: Record<string, unknown>) => JSON.stringify(sortKeysForObj(o)));\nsetDecoder(s => sortKeysForObj(JSON.parse(s)));\n","/**\n * @license\n * Copyright 2024 Google LLC\n *\n * Licensed under the Apache License, Version 2.0 (the \"License\");\n * you may not use this file except in compliance with the License.\n * You may obtain a copy of the License at\n *\n *   http://www.apache.org/licenses/LICENSE-2.0\n *\n * Unless required by applicable law or agreed to in writing, software\n * distributed under the License is distributed on an \"AS IS\" BASIS,\n * WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\n * See the License for the specific language governing permissions and\n * limitations under the License.\n */\n\nimport { type DataConnect } from '../../api/DataConnect';\nimport { QueryRef, QueryResult } from '../../api/query';\nimport {\n  QUERY_STR,\n  SerializedRef,\n  SOURCE_SERVER,\n  DataSource,\n  SOURCE_CACHE\n} from '../../api/Reference';\nimport { DataConnectSubscription } from '../../api.browser';\nimport { DataConnectCache, ServerValues } from '../../cache/Cache';\nimport { parseEntityIds } from '../../cache/cacheUtils';\nimport { EncodingMode } from '../../cache/EntityNode';\nimport {\n  DataConnectTransportInterface,\n  Extensions,\n  DataConnectExtensionWithMaxAge,\n  ExtensionsWithMaxAge,\n  SubscribeObserver,\n  DataConnectResponse\n} from '../../network';\nimport { decoderImpl, encoderImpl } from '../../util/encoder';\nimport {\n  Code,\n  DataConnectError,\n  DataConnectOperationError,\n  DataConnectOperationFailureResponse\n} from '../error';\n\nimport {\n  OnCompleteSubscription,\n  OnErrorSubscription,\n  OnResultSubscription\n} from './subscribe';\n\nexport function getRefSerializer<Data, Variables>(\n  queryRef: QueryRef<Data, Variables>,\n  data: Data,\n  source: DataSource,\n  fetchTime: string\n) {\n  return function toJSON(): SerializedRef<Data, Variables> {\n    return {\n      data,\n      refInfo: {\n        name: queryRef.name,\n        variables: queryRef.variables,\n        connectorConfig: {\n          projectId: queryRef.dataConnect.app.options.projectId!,\n          ...queryRef.dataConnect.getSettings()\n        }\n      },\n      fetchTime,\n      source\n    };\n  };\n}\n\nexport class QueryManager {\n  async preferCacheResults<Data, Variables>(\n    queryRef: QueryRef<Data, Variables>,\n    allowStale = false\n  ): Promise<QueryResult<Data, Variables>> {\n    let cacheResult: QueryResult<Data, Variables> | undefined;\n    try {\n      cacheResult = await this.fetchCacheResults(queryRef, allowStale);\n    } catch (e) {\n      // Ignore the error and try to fetch from the server.\n    }\n    if (cacheResult) {\n      return cacheResult;\n    }\n    return this.fetchServerResults(queryRef);\n  }\n  private callbacks = new Map<\n    string,\n    Array<DataConnectSubscription<unknown, unknown>>\n  >();\n  /**\n   * Map of serialized query keys to most recent Query Result. Used as a simple fallback cache\n   * for subsciptions if caching is not enabled.\n   */\n  private subscriptionCache = new Map<string, QueryResult<unknown, unknown>>();\n  constructor(\n    private transport: DataConnectTransportInterface,\n    private dc: DataConnect,\n    private cache?: DataConnectCache\n  ) {}\n  private queue: Array<Promise<unknown>> = [];\n  async waitForQueuedWrites(): Promise<void> {\n    for (const promise of this.queue) {\n      await promise;\n    }\n    this.queue = [];\n  }\n\n  updateSSR<Data, Variables>(updatedData: QueryResult<Data, Variables>): void {\n    this.queue.push(\n      this.updateCache(updatedData).then(async result =>\n        this.publishCacheResultsToSubscribers(result, updatedData.fetchTime)\n      )\n    );\n  }\n\n  async updateCache<Data, Variables>(\n    result: QueryResult<Data, Variables>,\n    extensions?: DataConnectExtensionWithMaxAge[]\n  ): Promise<string[]> {\n    await this.waitForQueuedWrites();\n    if (this.cache) {\n      const entityIds = parseEntityIds(result);\n      const updatedMaxAge = getMaxAgeFromExtensions(extensions);\n      if (updatedMaxAge !== undefined) {\n        this.cache.cacheSettings.maxAgeSeconds = updatedMaxAge;\n      }\n      return this.cache.update(\n        encoderImpl({\n          name: result.ref.name,\n          variables: result.ref.variables,\n          refType: QUERY_STR\n        }),\n        result.data as ServerValues,\n        entityIds\n      );\n    } else {\n      const key = encoderImpl({\n        name: result.ref.name,\n        variables: result.ref.variables,\n        refType: QUERY_STR\n      });\n      this.subscriptionCache.set(key, result);\n      return [key];\n    }\n  }\n\n  addSubscription<Data, Variables>(\n    queryRef: QueryRef<Data, Variables>,\n    onResultCallback: OnResultSubscription<Data, Variables>,\n    onCompleteCallback?: OnCompleteSubscription,\n    onErrorCallback?: OnErrorSubscription,\n    initialCache?: QueryResult<Data, Variables>\n  ): () => void {\n    const key = encoderImpl({\n      name: queryRef.name,\n      variables: queryRef.variables,\n      refType: QUERY_STR\n    });\n\n    const unsubscribe = (): void => {\n      if (this.callbacks.has(key)) {\n        const callbackList = this.callbacks.get(key)!;\n        const newList = callbackList.filter(\n          callback => callback !== subscription\n        );\n        this.callbacks.set(key, newList);\n\n        if (newList.length === 0) {\n          this.callbacks.delete(key);\n          this.transport.invokeUnsubscribe(queryRef.name, queryRef.variables);\n        }\n        onCompleteCallback?.();\n      }\n    };\n    const subscription: DataConnectSubscription<Data, Variables> = {\n      userCallback: onResultCallback,\n      errCallback: onErrorCallback,\n      unsubscribe\n    };\n\n    if (initialCache) {\n      this.updateSSR(initialCache);\n    }\n\n    const promise = this.preferCacheResults(queryRef, /*allowStale=*/ true);\n    // We want to ignore the error and let subscriptions handle it\n    promise.then(undefined, err => {});\n\n    if (this.callbacks.has(key)) {\n      this.callbacks\n        .get(key)!\n        .push(subscription as DataConnectSubscription<unknown, unknown>);\n    } else {\n      this.callbacks.set(key, [\n        subscription as DataConnectSubscription<unknown, unknown>\n      ]);\n\n      // only invoke subscription if we don't already have an active subscription\n      this.transport.invokeSubscribe<Data, Variables>(\n        this.makeSubscribeObserver(queryRef),\n        queryRef.name,\n        queryRef.variables\n      );\n    }\n\n    return unsubscribe;\n  }\n\n  async fetchServerResults<Data, Variables>(\n    queryRef: QueryRef<Data, Variables>\n  ): Promise<QueryResult<Data, Variables>> {\n    await this.waitForQueuedWrites();\n    const key = encoderImpl({\n      name: queryRef.name,\n      variables: queryRef.variables,\n      refType: QUERY_STR\n    });\n    try {\n      const result = await this.transport.invokeQuery<Data, Variables>(\n        queryRef.name,\n        queryRef.variables\n      );\n      const fetchTime = Date.now().toString();\n      const originalExtensions = result.extensions;\n      const queryResult: QueryResult<Data, Variables> = {\n        ...result,\n        ref: queryRef,\n        source: SOURCE_SERVER,\n        fetchTime,\n        data: result.data,\n        extensions: getDataConnectExtensionsWithoutMaxAge(originalExtensions),\n        toJSON: getRefSerializer(\n          queryRef,\n          result.data,\n          SOURCE_SERVER,\n          fetchTime\n        )\n      };\n      const updatedKeys = await this.updateCache(\n        queryResult,\n        originalExtensions?.dataConnect\n      );\n      this.publishDataToSubscribers(key, queryResult);\n      if (this.cache) {\n        await this.publishCacheResultsToSubscribers(updatedKeys, fetchTime);\n      } else {\n        this.subscriptionCache.set(key, queryResult);\n      }\n      return queryResult;\n    } catch (e) {\n      this.publishErrorToSubscribers(key, e);\n      throw e;\n    }\n  }\n\n  async fetchCacheResults<Data, Variables>(\n    queryRef: QueryRef<Data, Variables>,\n    allowStale = false\n  ): Promise<QueryResult<Data, Variables>> {\n    await this.waitForQueuedWrites();\n    let result: QueryResult<Data, Variables> | undefined | null;\n    if (!this.cache) {\n      result = await this.getFromSubscriberCache(queryRef);\n    } else {\n      result = await this.getFromResultTreeCache(queryRef, allowStale);\n    }\n    if (!result) {\n      throw new DataConnectError(\n        Code.OTHER,\n        'No cache entry found for query: ' + queryRef.name\n      );\n    }\n    const fetchTime = Date.now().toString();\n    const queryResult: QueryResult<Data, Variables> = {\n      ...result,\n      ref: queryRef,\n      source: SOURCE_CACHE,\n      fetchTime,\n      data: result.data,\n      extensions: result.extensions,\n      toJSON: getRefSerializer(queryRef, result.data, SOURCE_CACHE, fetchTime)\n    };\n    if (this.cache) {\n      const key = encoderImpl({\n        name: queryRef.name,\n        variables: queryRef.variables,\n        refType: QUERY_STR\n      });\n      await this.publishCacheResultsToSubscribers([key], fetchTime);\n    } else {\n      const key = encoderImpl({\n        name: queryRef.name,\n        variables: queryRef.variables,\n        refType: QUERY_STR\n      });\n      this.subscriptionCache.set(key, queryResult);\n      this.publishDataToSubscribers(key, queryResult);\n    }\n\n    return queryResult;\n  }\n\n  publishErrorToSubscribers(key: string, err: unknown): void {\n    this.callbacks.get(key)?.forEach(subscription => {\n      if (subscription.errCallback) {\n        subscription.errCallback(err as DataConnectError);\n      }\n    });\n  }\n\n  async getFromResultTreeCache<Data, Variables>(\n    queryRef: QueryRef<Data, Variables>,\n    allowStale = false\n  ): Promise<QueryResult<Data, Variables> | null> {\n    const key = encoderImpl({\n      name: queryRef.name,\n      variables: queryRef.variables,\n      refType: QUERY_STR\n    });\n    if (!this.cache || !(await this.cache.containsResultTree(key))) {\n      return null;\n    }\n    const cacheResult: Data = (await this.cache!.getResultJSON(key)) as Data;\n    const resultTree = await this.cache!.getResultTree(key);\n    if (!allowStale && resultTree!.isStale()) {\n      return null;\n    }\n    const result: QueryResult<Data, Variables> = {\n      source: SOURCE_CACHE,\n      ref: queryRef,\n      data: cacheResult,\n      toJSON: getRefSerializer(\n        queryRef,\n        cacheResult,\n        SOURCE_CACHE,\n        resultTree!.cachedAt.toString()\n      ),\n      fetchTime: resultTree!.cachedAt.toString()\n    };\n    (await this.cache!.getResultTree(key))!.updateAccessed();\n    return result;\n  }\n  async getFromSubscriberCache<Data, Variables>(\n    queryRef: QueryRef<Data, Variables>\n  ): Promise<QueryResult<Data, Variables> | undefined> {\n    const key = encoderImpl({\n      name: queryRef.name,\n      variables: queryRef.variables,\n      refType: QUERY_STR\n    });\n    if (!this.subscriptionCache.has(key)) {\n      return;\n    }\n    const result = this.subscriptionCache.get(key);\n    result!.source = SOURCE_CACHE;\n    result!.toJSON = getRefSerializer(\n      result!.ref,\n      result!.data,\n      SOURCE_CACHE,\n      result!.fetchTime\n    );\n    return result as QueryResult<Data, Variables>;\n  }\n\n  /** Call the registered onNext callbacks for the given key */\n  publishDataToSubscribers(\n    key: string,\n    queryResult: QueryResult<unknown, unknown>\n  ): void {\n    if (!this.callbacks.has(key)) {\n      return;\n    }\n    const subscribers = this.callbacks.get(key);\n    subscribers!.forEach(callback => {\n      callback.userCallback(queryResult);\n    });\n  }\n  async publishCacheResultsToSubscribers(\n    impactedQueries: string[],\n    fetchTime: string\n  ): Promise<void> {\n    if (!this.cache) {\n      return;\n    }\n    for (const query of impactedQueries) {\n      const callbacks = this.callbacks.get(query);\n      if (!callbacks) {\n        continue;\n      }\n      const newJson = (await this.cache.getResultTree(query))!\n        .getRootStub()\n        .toJSON(EncodingMode.hydrated);\n      const { name, variables } = decoderImpl(query) as unknown as QueryRef<\n        unknown,\n        unknown\n      >;\n      const queryRef: QueryRef<unknown, unknown> = {\n        dataConnect: this.dc,\n        refType: QUERY_STR,\n        name,\n        variables\n      };\n      this.publishDataToSubscribers(query, {\n        data: newJson,\n        fetchTime,\n        ref: queryRef,\n        source: SOURCE_CACHE,\n        toJSON: getRefSerializer(queryRef, newJson, SOURCE_CACHE, fetchTime)\n      });\n    }\n  }\n  enableEmulator(host: string, port: number): void {\n    this.transport.useEmulator(host, port);\n  }\n\n  /**\n   * Create a new {@link SubscribeObserver} for the given QueryRef. This will be passed to\n   * {@link DataConnectTransportInterface.invokeSubscribe | invokeSubscribe()} to notify the query\n   * layer of data update notifications or if the stream disconnected.\n   */\n  private makeSubscribeObserver<Data, Variables>(\n    queryRef: QueryRef<Data, Variables>\n  ): SubscribeObserver<Data> {\n    const key = encoderImpl({\n      name: queryRef.name,\n      variables: queryRef.variables,\n      refType: QUERY_STR\n    });\n    return {\n      onData: async response => {\n        await this.handleStreamNotification(key, response, queryRef);\n      },\n      onDisconnect: (code, reason) => {\n        this.handleStreamDisconnect(key, code, reason);\n      },\n      onError: error => {\n        this.publishErrorToSubscribers(key, error);\n      }\n    };\n  }\n\n  /**\n   * Handle a data update notification from the stream. Notify subscribers of results/errors, and\n   * update the cache.\n   */\n  private async handleStreamNotification<Data, Variables>(\n    key: string,\n    response: DataConnectResponse<Data>,\n    queryRef: QueryRef<Data, Variables>\n  ): Promise<void> {\n    if (response.errors && response.errors.length > 0) {\n      const stringified = JSON.stringify(\n        response.errors.map(e => {\n          if (e && typeof e === 'object') {\n            return {\n              message: (e as unknown as { message: string }).message,\n              code: (e as unknown as { code?: unknown }).code\n            };\n          }\n          return e;\n        })\n      );\n      const failureResponse: DataConnectOperationFailureResponse = {\n        errors: response.errors as [],\n        data: response.data as Record<string, unknown>\n      };\n      const error = new DataConnectOperationError(\n        'DataConnect error received from subscribe notification: ' +\n          stringified,\n        failureResponse\n      );\n      this.publishErrorToSubscribers(key, error);\n      return;\n    }\n\n    const fetchTime = Date.now().toString();\n    const queryResult: QueryResult<Data, Variables> = {\n      ref: queryRef,\n      source: SOURCE_SERVER,\n      fetchTime,\n      data: response.data,\n      extensions: getDataConnectExtensionsWithoutMaxAge(response.extensions),\n      toJSON: getRefSerializer(\n        queryRef,\n        response.data,\n        SOURCE_SERVER,\n        fetchTime\n      )\n    };\n    const updatedKeys = await this.updateCache(\n      queryResult,\n      response.extensions?.dataConnect\n    );\n    this.publishDataToSubscribers(key, queryResult);\n    if (this.cache) {\n      await this.publishCacheResultsToSubscribers(updatedKeys, fetchTime);\n    }\n  }\n\n  /**\n   * Handle a disconnect from the stream. Unsubscribe all callbacks for the given key.\n   */\n  private handleStreamDisconnect(\n    key: string,\n    code: string,\n    reason: string\n  ): void {\n    const error = new DataConnectError(code as Code, reason);\n    this.publishErrorToSubscribers(key, error);\n\n    const callbacks = this.callbacks.get(key);\n    if (callbacks) {\n      [...callbacks].forEach(cb => cb.unsubscribe());\n    }\n    return;\n  }\n}\n\nexport function getMaxAgeFromExtensions(\n  extensions: DataConnectExtensionWithMaxAge[] | undefined\n): number | undefined {\n  if (!extensions) {\n    return;\n  }\n  for (const extension of extensions) {\n    if (\n      'maxAge' in extension &&\n      extension.maxAge !== undefined &&\n      extension.maxAge !== null\n    ) {\n      if (extension.maxAge.endsWith('s')) {\n        return Number(\n          extension.maxAge.substring(0, extension.maxAge.length - 1)\n        );\n      }\n    }\n  }\n}\nfunction getDataConnectExtensionsWithoutMaxAge(\n  extensions: ExtensionsWithMaxAge\n): Extensions | undefined {\n  return {\n    dataConnect: extensions.dataConnect?.filter(\n      extension => 'entityId' in extension || 'entityIds' in extension\n    )\n  };\n}\n","/**\n * @license\n * Copyright 2026 Google LLC\n *\n * Licensed under the Apache License, Version 2.0 (the \"License\");\n * you may not use this file except in compliance with the License.\n * You may obtain a copy of the License at\n *\n *   http://www.apache.org/licenses/LICENSE-2.0\n *\n * Unless required by applicable law or agreed to in writing, software\n * distributed under the License is distributed on an \"AS IS\" BASIS,\n * WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\n * See the License for the specific language governing permissions and\n * limitations under the License.\n */\n\nimport { DataConnectOptions, TransportOptions } from '../api/DataConnect';\nimport { AppCheckTokenProvider } from '../core/AppCheckTokenProvider';\nimport { Code, DataConnectError } from '../core/error';\nimport { AuthTokenProvider } from '../core/FirebaseAuthProvider';\n\nimport { RESTTransport } from './rest';\nimport { AbstractDataConnectStreamTransport } from './stream/streamTransport';\nimport { WebSocketTransport } from './stream/websocket';\nimport {\n  CallerSdkType,\n  DataConnectResponse,\n  DataConnectResponseWithMaxAge,\n  DataConnectTransportInterface,\n  SubscribeObserver\n} from './transport';\n\n/**\n * Entry point for the transport layer. Manages routing between transport implementations.\n * @internal\n */\nexport class DataConnectTransportManager\n  implements DataConnectTransportInterface\n{\n  private restTransport: RESTTransport;\n  private streamTransport?: AbstractDataConnectStreamTransport;\n  private isUsingEmulator = false;\n\n  constructor(\n    private options: DataConnectOptions,\n    private apiKey?: string,\n    private appId?: string | null,\n    private authProvider?: AuthTokenProvider,\n    private appCheckProvider?: AppCheckTokenProvider,\n    private transportOptions?: TransportOptions,\n    private _isUsingGen = false,\n    private _callerSdkType?: CallerSdkType\n  ) {\n    this.restTransport = new RESTTransport(\n      options,\n      apiKey,\n      appId,\n      authProvider,\n      appCheckProvider,\n      transportOptions,\n      _isUsingGen,\n      _callerSdkType\n    );\n  }\n\n  /**\n   * Initializes the stream transport if it hasn't been already.\n   */\n  private initStreamTransport(): AbstractDataConnectStreamTransport {\n    if (!this.streamTransport) {\n      this.streamTransport = new WebSocketTransport(\n        this.options,\n        this.apiKey,\n        this.appId,\n        this.authProvider,\n        this.appCheckProvider,\n        this.transportOptions,\n        this._isUsingGen,\n        this._callerSdkType\n      );\n      if (this.isUsingEmulator && this.transportOptions) {\n        this.streamTransport.useEmulator(\n          this.transportOptions.host!,\n          this.transportOptions.port,\n          this.transportOptions.sslEnabled\n        );\n      }\n      this.streamTransport.onCloseCallback = () => {\n        this.streamTransport = undefined;\n      };\n    }\n    return this.streamTransport;\n  }\n\n  /**\n   * Returns true if the stream is in a healthy, ready connection state and has active subscriptions.\n   */\n  private executeShouldUseStream(): boolean {\n    return (\n      !!this.streamTransport &&\n      !this.streamTransport.isPendingClose &&\n      this.streamTransport.streamIsReady &&\n      this.streamTransport.hasActiveSubscriptions &&\n      !this.streamTransport.isUnableToConnect\n    );\n  }\n\n  /**\n   * Prefer to use Streaming Transport connection when one is available.\n   * @inheritdoc\n   */\n  invokeQuery<Data, Variables>(\n    queryName: string,\n    body?: Variables\n  ): Promise<DataConnectResponseWithMaxAge<Data>> {\n    if (this.executeShouldUseStream()) {\n      return this.streamTransport!.invokeQuery<Data, Variables>(\n        queryName,\n        body\n      ).catch(err => {\n        if (this.executeShouldUseStream()) {\n          throw err;\n        }\n        return this.restTransport.invokeQuery<Data, Variables>(queryName, body);\n      });\n    }\n    return this.restTransport.invokeQuery(queryName, body);\n  }\n\n  /**\n   * Prefer to use Streaming Transport connection when one is available.\n   * @inheritdoc\n   */\n  invokeMutation<Data, Variables>(\n    queryName: string,\n    body?: Variables\n  ): Promise<DataConnectResponse<Data>> {\n    if (this.executeShouldUseStream()) {\n      return this.streamTransport!.invokeMutation<Data, Variables>(\n        queryName,\n        body\n      ).catch(err => {\n        if (this.executeShouldUseStream()) {\n          throw err;\n        }\n        return this.restTransport.invokeMutation<Data, Variables>(\n          queryName,\n          body\n        );\n      });\n    }\n    return this.restTransport.invokeMutation(queryName, body);\n  }\n\n  invokeSubscribe<Data, Variables>(\n    observer: SubscribeObserver<Data>,\n    queryName: string,\n    body?: Variables\n  ): void {\n    const streamTransport = this.initStreamTransport();\n    if (streamTransport.isUnableToConnect) {\n      throw new DataConnectError(\n        Code.OTHER,\n        'Unable to connect streaming connection to server. Subscriptions are unavailable.'\n      );\n    }\n    streamTransport.invokeSubscribe(observer, queryName, body);\n  }\n\n  invokeUnsubscribe<Variables>(queryName: string, body?: Variables): void {\n    if (this.streamTransport) {\n      this.streamTransport.invokeUnsubscribe(queryName, body);\n    }\n  }\n\n  useEmulator(host: string, port?: number, sslEnabled?: boolean): void {\n    this.isUsingEmulator = true;\n    this.transportOptions = { host, port, sslEnabled };\n    this.restTransport.useEmulator(host, port, sslEnabled);\n    if (this.streamTransport) {\n      this.streamTransport.useEmulator(host, port, sslEnabled);\n    }\n  }\n\n  onAuthTokenChanged(token: string | null): void {\n    this.restTransport.onAuthTokenChanged(token);\n    if (this.streamTransport) {\n      this.streamTransport.onAuthTokenChanged(token);\n    }\n  }\n\n  _setCallerSdkType(callerSdkType: CallerSdkType): void {\n    this._callerSdkType = callerSdkType;\n    this.restTransport._setCallerSdkType(callerSdkType);\n    if (this.streamTransport) {\n      this.streamTransport._setCallerSdkType(callerSdkType);\n    }\n  }\n}\n","/**\n * @license\n * Copyright 2024 Google LLC\n *\n * Licensed under the Apache License, Version 2.0 (the \"License\");\n * you may not use this file except in compliance with the License.\n * You may obtain a copy of the License at\n *\n *   http://www.apache.org/licenses/LICENSE-2.0\n *\n * Unless required by applicable law or agreed to in writing, software\n * distributed under the License is distributed on an \"AS IS\" BASIS,\n * WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\n * See the License for the specific language governing permissions and\n * limitations under the License.\n */\n\nimport { DataConnectTransportInterface } from '../network';\n\nimport { DataConnect } from './DataConnect';\nimport {\n  DataConnectResult,\n  MUTATION_STR,\n  OperationRef,\n  SOURCE_SERVER\n} from './Reference';\n\nexport interface MutationRef<Data, Variables>\n  extends OperationRef<Data, Variables> {\n  refType: typeof MUTATION_STR;\n}\n\n/**\n * Creates a `MutationRef`\n * @param dcInstance Data Connect instance\n * @param mutationName name of mutation\n */\nexport function mutationRef<Data>(\n  dcInstance: DataConnect,\n  mutationName: string\n): MutationRef<Data, undefined>;\n/**\n *\n * @param dcInstance Data Connect instance\n * @param mutationName name of mutation\n * @param variables variables to send with mutation\n */\nexport function mutationRef<Data, Variables>(\n  dcInstance: DataConnect,\n  mutationName: string,\n  variables: Variables\n): MutationRef<Data, Variables>;\n/**\n *\n * @param dcInstance Data Connect instance\n * @param mutationName name of mutation\n * @param variables variables to send with mutation\n * @returns `MutationRef`\n */\nexport function mutationRef<Data, Variables>(\n  dcInstance: DataConnect,\n  mutationName: string,\n  variables?: Variables\n): MutationRef<Data, Variables> {\n  dcInstance.setInitialized();\n  const ref: MutationRef<Data, Variables> = {\n    dataConnect: dcInstance,\n    name: mutationName,\n    refType: MUTATION_STR,\n    variables: variables as Variables\n  };\n  return ref;\n}\n\n/**\n * @internal\n */\nexport class MutationManager {\n  private _inflight: Array<Promise<unknown>> = [];\n  constructor(private _transport: DataConnectTransportInterface) {}\n  executeMutation<Data, Variables>(\n    mutationRef: MutationRef<Data, Variables>\n  ): MutationPromise<Data, Variables> {\n    const result = this._transport.invokeMutation<Data, Variables>(\n      mutationRef.name,\n      mutationRef.variables\n    );\n    const withRefPromise = result.then(res => {\n      const obj: MutationResult<Data, Variables> = {\n        ...res, // Double check that the result is result.data, not just result\n        source: SOURCE_SERVER,\n        ref: mutationRef,\n        fetchTime: Date.now().toLocaleString()\n      };\n      return obj;\n    });\n    this._inflight.push(result);\n    const removePromise = (): Array<Promise<unknown>> =>\n      (this._inflight = this._inflight.filter(promise => promise !== result));\n    result.then(removePromise, removePromise);\n    return withRefPromise;\n  }\n}\n\n/**\n * Mutation Result from `executeMutation`\n */\nexport interface MutationResult<Data, Variables>\n  extends DataConnectResult<Data, Variables> {\n  ref: MutationRef<Data, Variables>;\n}\n/**\n * Mutation return value from `executeMutation`\n */\nexport interface MutationPromise<Data, Variables>\n  extends Promise<MutationResult<Data, Variables>> {\n  // reserved for special actions like cancellation\n}\n\n/**\n * Execute Mutation\n * @param mutationRef mutation to execute\n * @returns `MutationRef`\n */\nexport function executeMutation<Data, Variables>(\n  mutationRef: MutationRef<Data, Variables>\n): MutationPromise<Data, Variables> {\n  return mutationRef.dataConnect._mutationManager.executeMutation(mutationRef);\n}\n","/**\n * @license\n * Copyright 2024 Google LLC\n *\n * Licensed under the Apache License, Version 2.0 (the \"License\");\n * you may not use this file except in compliance with the License.\n * You may obtain a copy of the License at\n *\n *   http://www.apache.org/licenses/LICENSE-2.0\n *\n * Unless required by applicable law or agreed to in writing, software\n * distributed under the License is distributed on an \"AS IS\" BASIS,\n * WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\n * See the License for the specific language governing permissions and\n * limitations under the License.\n */\n\nimport {\n  FirebaseApp,\n  _getProvider,\n  _removeServiceInstance,\n  getApp\n} from '@firebase/app';\nimport { AppCheckInternalComponentName } from '@firebase/app-check-interop-types';\nimport { FirebaseAuthInternalName } from '@firebase/auth-interop-types';\nimport { Provider } from '@firebase/component';\nimport { isCloudWorkstation, pingServer } from '@firebase/util';\n\nimport { DataConnectCache, MemoryStub } from '../cache/Cache';\nimport { InternalCacheProvider } from '../cache/CacheProvider';\nimport { AppCheckTokenProvider } from '../core/AppCheckTokenProvider';\nimport { Code, DataConnectError } from '../core/error';\nimport {\n  AuthTokenProvider,\n  FirebaseAuthProvider\n} from '../core/FirebaseAuthProvider';\nimport { QueryManager } from '../core/query/QueryManager';\nimport { logDebug, logError } from '../logger';\nimport {\n  DataConnectTransportInterface,\n  TransportClass,\n  CallerSdkType,\n  CallerSdkTypeEnum\n} from '../network';\nimport { DataConnectTransportManager } from '../network/manager';\nimport { PROD_HOST } from '../util/url';\n\nimport { MutationManager } from './Mutation';\n\n/**\n * Connector Config for calling Data Connect backend.\n */\nexport interface ConnectorConfig {\n  location: string;\n  connector: string;\n  service: string;\n}\n\n/**\n * Options to connect to emulator\n */\nexport interface TransportOptions {\n  host: string;\n  sslEnabled?: boolean;\n  port?: number;\n}\n\nconst FIREBASE_DATA_CONNECT_EMULATOR_HOST_VAR =\n  'FIREBASE_DATA_CONNECT_EMULATOR_HOST';\n\n/**\n *\n * @param fullHost\n * @returns TransportOptions\n * @internal\n */\nexport function parseOptions(fullHost: string): TransportOptions {\n  const [protocol, hostName] = fullHost.split('://');\n  const isSecure = protocol === 'https';\n  const [host, portAsString] = hostName.split(':');\n  const port = Number(portAsString);\n  return { host, port, sslEnabled: isSecure };\n}\n/**\n * DataConnectOptions including project id\n */\nexport interface DataConnectOptions extends ConnectorConfig {\n  projectId: string;\n}\n\n/**\n * Class representing Firebase Data Connect\n */\nexport class DataConnect {\n  _queryManager!: QueryManager;\n  _mutationManager!: MutationManager;\n  isEmulator = false;\n  _initialized = false;\n  private _transport!: DataConnectTransportInterface;\n  private _transportClass: TransportClass | undefined;\n  private _transportOptions?: TransportOptions;\n  private _authTokenProvider?: AuthTokenProvider;\n  _isUsingGeneratedSdk: boolean = false;\n  _callerSdkType: CallerSdkType = CallerSdkTypeEnum.Base;\n  private _appCheckTokenProvider?: AppCheckTokenProvider;\n  private _cacheSettings?: CacheSettings;\n  /**\n   * @internal\n   */\n  private cache?: DataConnectCache;\n  // @internal\n  constructor(\n    public readonly app: FirebaseApp,\n    // TODO(mtewani): Replace with _dataConnectOptions in the future\n    private readonly dataConnectOptions: DataConnectOptions,\n    private readonly _authProvider: Provider<FirebaseAuthInternalName>,\n    private readonly _appCheckProvider: Provider<AppCheckInternalComponentName>\n  ) {\n    if (typeof process !== 'undefined' && process.env) {\n      const host = process.env[FIREBASE_DATA_CONNECT_EMULATOR_HOST_VAR];\n      if (host) {\n        logDebug('Found custom host. Using emulator');\n        this.isEmulator = true;\n        this._transportOptions = parseOptions(host);\n      }\n    }\n  }\n  /**\n   * @internal\n   */\n  getCache(): DataConnectCache | undefined {\n    return this.cache;\n  }\n  // @internal\n  _useGeneratedSdk(): void {\n    if (!this._isUsingGeneratedSdk) {\n      this._isUsingGeneratedSdk = true;\n    }\n  }\n  _setCallerSdkType(callerSdkType: CallerSdkType): void {\n    this._callerSdkType = callerSdkType;\n    if (this._initialized) {\n      this._transport._setCallerSdkType(callerSdkType);\n    }\n  }\n  _delete(): Promise<void> {\n    _removeServiceInstance(\n      this.app,\n      'data-connect',\n      JSON.stringify(this.getSettings())\n    );\n    return Promise.resolve();\n  }\n\n  // @internal\n  getSettings(): ConnectorConfig {\n    const copy = JSON.parse(JSON.stringify(this.dataConnectOptions));\n    delete copy.projectId;\n    return copy;\n  }\n\n  /**\n   * @internal\n   */\n  setCacheSettings(cacheSettings: CacheSettings): void {\n    this._cacheSettings = cacheSettings;\n  }\n\n  // @internal\n  setInitialized(): void {\n    if (this._initialized) {\n      return;\n    }\n    if (this._transportClass === undefined) {\n      logDebug(\n        'transportClass not provided. Defaulting to DataConnectTransportManager.'\n      );\n      this._transportClass = DataConnectTransportManager;\n    }\n\n    this._authTokenProvider = new FirebaseAuthProvider(\n      this.app.name,\n      this.app.options,\n      this._authProvider\n    );\n    const connectorConfig: ConnectorConfig = {\n      connector: this.dataConnectOptions.connector,\n      service: this.dataConnectOptions.service,\n      location: this.dataConnectOptions.location\n    };\n    if (this._cacheSettings) {\n      this.cache = new DataConnectCache(\n        this._authTokenProvider,\n        this.app.options.projectId!,\n        connectorConfig,\n        this._transportOptions?.host || PROD_HOST,\n        this._cacheSettings\n      );\n    }\n\n    if (this._appCheckProvider) {\n      this._appCheckTokenProvider = new AppCheckTokenProvider(\n        this.app,\n        this._appCheckProvider\n      );\n    }\n\n    this._transport = new this._transportClass(\n      this.dataConnectOptions,\n      this.app.options.apiKey,\n      this.app.options.appId,\n      this._authTokenProvider,\n      this._appCheckTokenProvider,\n      undefined,\n      this._isUsingGeneratedSdk,\n      this._callerSdkType\n    );\n    if (this._transportOptions) {\n      this._transport.useEmulator(\n        this._transportOptions.host,\n        this._transportOptions.port,\n        this._transportOptions.sslEnabled\n      );\n    }\n\n    this._queryManager = new QueryManager(this._transport, this, this.cache);\n    this._mutationManager = new MutationManager(this._transport);\n    this._initialized = true;\n  }\n\n  // @internal\n  enableEmulator(transportOptions: TransportOptions): void {\n    if (\n      this._transportOptions &&\n      this._initialized &&\n      !areTransportOptionsEqual(this._transportOptions, transportOptions)\n    ) {\n      logError('enableEmulator called after initialization');\n      throw new DataConnectError(\n        Code.ALREADY_INITIALIZED,\n        'DataConnect instance already initialized!'\n      );\n    }\n    this._transportOptions = transportOptions;\n    this.isEmulator = true;\n  }\n}\n\n/**\n * @internal\n * @param transportOptions1\n * @param transportOptions2\n * @returns\n */\nexport function areTransportOptionsEqual(\n  transportOptions1: TransportOptions,\n  transportOptions2: TransportOptions\n): boolean {\n  return (\n    transportOptions1.host === transportOptions2.host &&\n    transportOptions1.port === transportOptions2.port &&\n    transportOptions1.sslEnabled === transportOptions2.sslEnabled\n  );\n}\n\n/**\n * Connect to the DataConnect Emulator\n * @param dc Data Connect instance\n * @param host host of emulator server\n * @param port port of emulator server\n * @param sslEnabled use https\n */\nexport function connectDataConnectEmulator(\n  dc: DataConnect,\n  host: string,\n  port?: number,\n  sslEnabled = false\n): void {\n  // Workaround to get cookies in Firebase Studio\n  if (isCloudWorkstation(host)) {\n    void pingServer(`https://${host}${port ? `:${port}` : ''}`);\n  }\n  dc.enableEmulator({ host, port, sslEnabled });\n}\n\nexport interface DataConnectSettings {\n  cacheSettings?: CacheSettings;\n}\n\n/**\n * Initialize DataConnect instance\n * @param options ConnectorConfig\n */\nexport function getDataConnect(\n  options: ConnectorConfig,\n  settings?: DataConnectSettings\n): DataConnect;\nexport function getDataConnect(options: ConnectorConfig): DataConnect;\n/**\n * Initialize DataConnect instance\n * @param app FirebaseApp to initialize to.\n * @param connectorConfig ConnectorConfig\n */\nexport function getDataConnect(\n  app: FirebaseApp,\n  connectorConfig: ConnectorConfig\n): DataConnect;\n\n/**\n * Initialize DataConnect instance\n * @param app FirebaseApp to initialize to.\n * @param connectorConfig ConnectorConfig\n */\nexport function getDataConnect(\n  app: FirebaseApp,\n  connectorConfig: ConnectorConfig,\n  settings: DataConnectSettings\n): DataConnect;\n\nexport function getDataConnect(\n  appOrConnectorConfig: FirebaseApp | ConnectorConfig,\n  settingsOrConnectorConfig?: ConnectorConfig | DataConnectSettings,\n  settings?: DataConnectSettings\n): DataConnect {\n  let app: FirebaseApp;\n  let connectorConfig: ConnectorConfig;\n  let realSettings: DataConnectSettings;\n  if ('location' in appOrConnectorConfig) {\n    connectorConfig = appOrConnectorConfig;\n    app = getApp();\n    realSettings = settingsOrConnectorConfig as DataConnectSettings;\n  } else {\n    app = appOrConnectorConfig;\n    connectorConfig = settingsOrConnectorConfig as ConnectorConfig;\n    realSettings = settings as DataConnectSettings;\n  }\n\n  if (!app || Object.keys(app).length === 0) {\n    app = getApp();\n  }\n\n  // Options to store in Firebase Component Provider.\n  const serializedOptions = {\n    ...connectorConfig,\n    projectId: app.options.projectId\n  };\n\n  // We should sort the keys before initialization.\n  const sortedSerialized = Object.fromEntries(\n    Object.entries(serializedOptions).sort()\n  );\n\n  const provider = _getProvider(app, 'data-connect');\n  const identifier = JSON.stringify(sortedSerialized);\n  if (provider.isInitialized(identifier)) {\n    const dcInstance = provider.getImmediate({ identifier });\n    const options = provider.getOptions(identifier);\n    const optionsValid = Object.keys(options).length > 0;\n    if (optionsValid) {\n      logDebug('Re-using cached instance');\n      return dcInstance;\n    }\n  }\n  validateDCOptions(connectorConfig);\n\n  logDebug('Creating new DataConnect instance');\n  // Initialize with options.\n  const dataConnect = provider.initialize({\n    instanceIdentifier: identifier,\n    options: Object.fromEntries(\n      Object.entries({\n        ...sortedSerialized\n      }).sort()\n    )\n  });\n  if (realSettings?.cacheSettings) {\n    dataConnect.setCacheSettings(realSettings.cacheSettings);\n  }\n  return dataConnect;\n}\n\n/**\n *\n * @param dcOptions\n * @returns {void}\n * @internal\n */\nexport function validateDCOptions(dcOptions: ConnectorConfig): boolean {\n  const fields = ['connector', 'location', 'service'];\n  if (!dcOptions) {\n    throw new DataConnectError(Code.INVALID_ARGUMENT, 'DC Option Required');\n  }\n  fields.forEach(field => {\n    if (\n      dcOptions[field as keyof ConnectorConfig] === null ||\n      dcOptions[field as keyof ConnectorConfig] === undefined\n    ) {\n      throw new DataConnectError(Code.INVALID_ARGUMENT, `${field} Required`);\n    }\n  });\n  return true;\n}\n\n/**\n * Delete DataConnect instance\n * @param dataConnect DataConnect instance\n * @returns\n */\nexport function terminate(dataConnect: DataConnect): Promise<void> {\n  return dataConnect._delete();\n  // TODO(mtewani): Stop pending tasks\n}\nexport const StorageType = {\n  MEMORY: 'MEMORY'\n} as const;\n\nexport type StorageType = (typeof StorageType)[keyof typeof StorageType];\n\nexport interface CacheSettings {\n  cacheProvider: CacheProvider<StorageType>;\n  maxAgeSeconds?: number;\n}\nexport interface CacheProvider<T extends StorageType> {\n  type: T;\n  /**\n   * @internal\n   */\n  initialize(cacheId: string): InternalCacheProvider;\n}\n\nexport function makeMemoryCacheProvider(): CacheProvider<'MEMORY'> {\n  return new MemoryStub();\n}\n","/**\n * @license\n * Copyright 2024 Google LLC\n *\n * Licensed under the Apache License, Version 2.0 (the \"License\");\n * you may not use this file except in compliance with the License.\n * You may obtain a copy of the License at\n *\n *   http://www.apache.org/licenses/LICENSE-2.0\n *\n * Unless required by applicable law or agreed to in writing, software\n * distributed under the License is distributed on an \"AS IS\" BASIS,\n * WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\n * See the License for the specific language governing permissions and\n * limitations under the License.\n */\n// eslint-disable-next-line import/no-extraneous-dependencies\nimport {\n  _registerComponent,\n  registerVersion,\n  SDK_VERSION\n} from '@firebase/app';\nimport { Component, ComponentType } from '@firebase/component';\n\nimport { name, version } from '../package.json';\nimport { setSDKVersion } from '../src/core/version';\n\nimport { DataConnect, ConnectorConfig } from './api/DataConnect';\nimport { Code, DataConnectError } from './core/error';\n\nexport function registerDataConnect(variant?: string): void {\n  setSDKVersion(SDK_VERSION);\n  _registerComponent(\n    new Component(\n      'data-connect',\n      (container, { instanceIdentifier: connectorConfigStr, options }) => {\n        const app = container.getProvider('app').getImmediate()!;\n        const authProvider = container.getProvider('auth-internal');\n        const appCheckProvider = container.getProvider('app-check-internal');\n        let newOpts = options as ConnectorConfig;\n        if (connectorConfigStr) {\n          newOpts = {\n            ...JSON.parse(connectorConfigStr),\n            ...newOpts\n          };\n        }\n        if (!app.options.projectId) {\n          throw new DataConnectError(\n            Code.INVALID_ARGUMENT,\n            'Project ID must be provided. Did you pass in a proper projectId to initializeApp?'\n          );\n        }\n        return new DataConnect(\n          app,\n          { ...newOpts, projectId: app.options.projectId! },\n          authProvider,\n          appCheckProvider\n        );\n      },\n      ComponentType.PUBLIC\n    ).setMultipleInstances(true)\n  );\n  registerVersion(name, version, variant);\n  // BUILD_TARGET will be replaced by values like esm, cjs, etc during the compilation\n  registerVersion(name, version, '__BUILD_TARGET__');\n}\n","/**\n * @license\n * Copyright 2025 Google LLC\n *\n * Licensed under the Apache License, Version 2.0 (the \"License\");\n * you may not use this file except in compliance with the License.\n * You may o